                        const { data: profile } = await supabase
                            .from('profiles')
                            .select('*')
                            .eq('id', data.user.id)
                            .single();

                        if (profile) {
                            return {
                                id: profile.id,
                                firstName: profile.first_name,
                                lastName: profile.last_name,
                                email: profile.email,
                                phone: profile.phone,
                                type: profile.type,
                                address: profile.address,
                                points: profile.points,
                                collections: profile.collections,
                                badges: profile.badges,
                                subscription: profile.subscription,
                                companyName: profile.company_name,
                                sector: profile.sector,
                                permissions: profile.permissions,
                                zone: profile.zone,
                                vehicleType: profile.vehicle_type,
                                housingType: profile.housing_type
                            } as User;
                        }
                    }
                }
            } catch (error) {
                console.error("Supabase Login Error:", error);
            }
        }

        // 2. Fallback Local Storage
        await new Promise(r => setTimeout(r, 800));
        const users = getCollection<User>(KEYS.USERS);
        const user = users.find(u => u.email === identifier || u.phone === identifier);
        return user || null;
    },

    register: async (user: User, password?: string): Promise<User> => {
        // 1. Supabase Register
        if (isSupabaseConfigured() && supabase && user.email && password) {
            try {
                const { data, error } = await supabase.auth.signUp({
                    email: user.email,
                    password: password,
                    options: {
                        data: {
                            first_name: user.firstName,
                            last_name: user.lastName,
                            type: user.type,
                            phone: user.phone
                        }
                    }
                });

                if (error) throw error;

                if (data.user) {
                    return { ...user, id: data.user.id };
                }
            } catch (error) {
                console.error("Supabase Register Error:", error);
                throw error;
            }
        }

        // 2. Local Storage
        const users = getCollection<User>(KEYS.USERS);
        const newUser = { ...user, id: `u-${Date.now()}` };
        users.unshift(newUser);
        saveCollection(KEYS.USERS, users);
        return newUser;
    },

    getAll: async (): Promise<User[]> => {
        if (isSupabaseConfigured() && supabase) {
            const { data } = await supabase.from('profiles').select('*');
