                                             <label key={perm.key} className={`flex items-start gap-2 cursor-pointer p-2 rounded-lg transition-all border ${userForm.permissions.includes(perm.key) ? 'bg-white dark:bg-gray-800 border-blue-200 dark:border-blue-900 shadow-sm' : 'border-transparent hover:bg-white dark:hover:bg-gray-800'}`}>
                                                 <div className={`mt-0.5 w-5 h-5 rounded border flex items-center justify-center transition-colors shrink-0 ${userForm.permissions.includes(perm.key) ? 'bg-[#2962FF] border-[#2962FF]' : 'border-gray-400 bg-white dark:bg-gray-900'}`}>
                                                     {userForm.permissions.includes(perm.key) && <CheckSquare size={14} className="text-white" />}
                                                 </div>
                                                 <input 
                                                    type="checkbox" 
                                                    className="hidden" 
                                                    checked={userForm.permissions.includes(perm.key)}
                                                    onChange={() => togglePermission(perm.key)}
                                                 />
                                                 <div>
                                                     <span className={`text-xs font-bold block ${userForm.permissions.includes(perm.key) ? 'text-blue-700 dark:text-blue-300' : 'text-gray-700 dark:text-gray-300'}`}>
                                                         {perm.label}
                                                     </span>
                                                     <span className="text-[10px] text-gray-500 dark:text-gray-400 leading-tight">
                                                         {perm.description}
                                                     </span>
                                                 </div>
                                             </label>
                                         ))}
                                     </div>
                                 </div>
                             )}

                             <div className="flex gap-3 pt-4 border-t border-gray-100 dark:border-gray-700 mt-4">
                                 <button type="button" onClick={() => setShowUserModal(false)} className="flex-1 py-3 bg-gray-100 dark:bg-gray-700 rounded-xl font-bold text-gray-600 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600 transition-colors">Annuler</button>
                                 <button type="submit" className="flex-1 py-3 bg-[#00C853] text-white rounded-xl font-bold hover:bg-green-600 transition-colors shadow-lg shadow-green-500/20">
                                     {isEditing ? 'Mettre à jour' : 'Créer'}
                                 </button>
                             </div>
                         </form>
                     </div>
                 </div>
             )}
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { ChevronRight, ArrowLeft, Home, Building, Truck, Check, CreditCard, MapPin, LogIn, User as UserIcon, Shield, Lock, Phone, Eye, EyeOff, AlertCircle, Mail, Smartphone, RefreshCw, KeyRound, Globe, Loader2, X } from 'lucide-react';
import { UserType, User } from '../types';
import { LegalDocs } from './LegalDocs';
import { UserAPI } from '../services/api';
import { isSupabaseConfigured } from '../services/supabaseClient';

interface OnboardingProps {
    onComplete: (user: Partial<User>) => void;
    appLogo?: string;
    onToast?: (msg: string, type: 'success' | 'error' | 'info') => void;
}

export const Onboarding: React.FC<OnboardingProps> = ({ onComplete, appLogo = './logo.png', onToast }) => {
    const [step, setStep] = useState(1);
    const [showLogin, setShowLogin] = useState(false);
    const [showForgotPass, setShowForgotPass] = useState(false);

    // Legal Docs State
    const [acceptedTerms, setAcceptedTerms] = useState(false);
    const [legalModalType, setLegalModalType] = useState<'terms' | 'privacy' | null>(null);

    // Login State
    const [loginRole, setLoginRole] = useState<UserType.CITIZEN | UserType.COLLECTOR | UserType.ADMIN>(UserType.CITIZEN);
    const [loginIdentifier, setLoginIdentifier] = useState('');
    const [loginPassword, setLoginPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [isLoggingIn, setIsLoggingIn] = useState(false);
    const [loginError, setLoginError] = useState<string | null>(null);

    // Forgot Password State
    const [resetStep, setResetStep] = useState<1 | 2>(1); // 1: Email, 2: New Password
    const [resetCode, setResetCode] = useState(''); // Code de vérification
    const [newResetPassword, setNewResetPassword] = useState('');
    const [confirmResetPassword, setConfirmResetPassword] = useState('');

    // Register State
    const [regStep, setRegStep] = useState(1);
    const [otpCode, setOtpCode] = useState(['', '', '', '', '', '']);
    const [isVerifyingOTP, setIsVerifyingOTP] = useState(false);
    const [otpTimer, setOtpTimer] = useState(0);

    const [registerPassword, setRegisterPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [passwordStrength, setPasswordStrength] = useState(0); 

    const [formData, setFormData] = useState<Partial<User>>({
        firstName: '',
        lastName: '',
        phone: '',
        email: '',
        type: UserType.CITIZEN,
        address: '',
        subscription: 'plus',
        companyName: '',
        companyPhone: '',
        sector: '',
        vehicleType: '',
        housingType: 'Maison'
    });

    // --- Helpers (omitted for brevity, same logic) ---
    const handleNext = () => setStep(prev => prev + 1);
    const handleBack = () => setStep(prev => prev - 1);
    const updateData = (key: string, value: any) => setFormData(prev => ({ ...prev, [key]: value }));
    const calculatePasswordStrength = (pass: string) => {
        let strength = 0;
        if (pass.length >= 8) strength++;
        if (/[A-Z]/.test(pass)) strength++;
        if (/[0-9]/.test(pass)) strength++;
        if (/[0-9]/.test(pass)) strength++;
        if (/[^A-Za-z0-9]/.test(pass)) strength++;
        setPasswordStrength(strength);
    };
    const handlePasswordInput = (val: string) => {
        setRegisterPassword(val);
        calculatePasswordStrength(val);
    };

    // --- OTP Logic ---
    const startOtpTimer = () => {
        setOtpTimer(60);
        const interval = setInterval(() => {
            setOtpTimer((prev) => {
                if (prev <= 1) {
                    clearInterval(interval);
                    return 0;
                }
                return prev - 1;
            });
        }, 1000);
    };

    const handleSendOTP = async () => {
        if (!formData.firstName || !formData.lastName || !formData.phone) {
            if(onToast) onToast("Veuillez remplir tous les champs obligatoires", "error");
            return;
        }
        setIsVerifyingOTP(true);
        setTimeout(() => {
            setIsVerifyingOTP(false);
            setRegStep(2);
            startOtpTimer();
            if(onToast) onToast(`Code envoyé au ${formData.phone}`, "info");
        }, 1500);
    };

    const handleVerifyOTP = async () => {
        const code = otpCode.join('');
        if (code.length !== 6) {
            if(onToast) onToast("Code incomplet", "error");
            return;
        }
        setIsVerifyingOTP(true);
        const isValid = await UserAPI.verifyOTP(code);
        setIsVerifyingOTP(false);
        if (isValid) {
            if(onToast) onToast("Numéro vérifié avec succès", "success");
            setRegStep(3);
        } else {
            if(onToast) onToast("Code incorrect (Essayez 123456)", "error");
            setOtpCode(['', '', '', '', '', '']);
        }
    };

    const handleOtpChange = (index: number, value: string) => {
        if (isNaN(Number(value))) return;
        const newOtp = [...otpCode];
        newOtp[index] = value;
        setOtpCode(newOtp);
        if (value && index < 5) {
            const nextInput = document.getElementById(`otp-${index + 1}`);
            nextInput?.focus();
        }
    };

    // --- Login Logic ---
    const handleLoginSubmit = async () => {
        if (!loginIdentifier || !loginPassword) {
            setLoginError("Veuillez remplir tous les champs");
            return;
        }
        setIsLoggingIn(true);
        setLoginError(null);
        try {
            const user = await UserAPI.login(loginIdentifier, loginPassword);
            if (user) {
                if(onToast) onToast(`Bon retour, ${user.firstName} !`, "success");
                onComplete(user);
            } else {
                setLoginError("Identifiants incorrects ou utilisateur introuvable.");
                if(onToast) onToast("Échec de connexion", "error");
            }
        } catch (err) {
            console.error(err);
            setLoginError("Une erreur de connexion est survenue.");
        } finally {
            setIsLoggingIn(false);
        }
    };

    // --- Forgot Password Logic ---
    const handleForgotPassRequest = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!loginIdentifier) {
            if(onToast) onToast("Veuillez saisir votre identifiant", "error");
            return;
        }
        setIsLoggingIn(true);
        try {
            await UserAPI.resetPassword(loginIdentifier);
            setResetStep(2);
            if(onToast) onToast("Code de réinitialisation envoyé.", "success");
        } catch (e) {
            if(onToast) onToast("Erreur lors de la demande.", "error");
        } finally {
            setIsLoggingIn(false);
        }
    };

    const handleResetConfirm = async (e: React.FormEvent) => {
        e.preventDefault();
        if (newResetPassword !== confirmResetPassword) {
            if(onToast) onToast("Les mots de passe ne correspondent pas", "error");
            return;
        }
        if (newResetPassword.length < 6) {
            if(onToast) onToast("Mot de passe trop court", "error");
            return;
        }

        setIsLoggingIn(true);
        try {
            // Simulation API Call
            await UserAPI.confirmPasswordReset(loginIdentifier, newResetPassword);
            setShowForgotPass(false);
            setResetStep(1);
            setLoginPassword('');
            if(onToast) onToast("Mot de passe modifié avec succès. Connectez-vous.", "success");
        } catch (e) {
            if(onToast) onToast("Erreur lors de la modification.", "error");
        } finally {
            setIsLoggingIn(false);
        }
    };

    // --- Register Submit ---
    const handleRegisterSubmit = async () => {
        try {
            const newUser: User = {
                id: '',
                firstName: formData.firstName || '',
                lastName: formData.lastName || '',
                email: formData.email,
                phone: formData.phone || '',
                type: formData.type || UserType.CITIZEN,
                address: formData.address || '',
                points: 100,
                collections: 0,
                badges: 0,
                subscription: formData.subscription || 'standard',
                companyName: formData.companyName,
                sector: formData.sector,
                housingType: formData.housingType
            };
            await UserAPI.register(newUser, registerPassword);
            if(onToast) onToast("Compte créé avec succès !", "success");
            onComplete(newUser);
        } catch (error) {
            console.error("Registration failed", error);
            if(onToast) onToast("Erreur lors de la création du compte.", "error");
        }
    };

    // --- RENDER FUNCTIONS ---

    const renderWelcome = () => (
        <div className="flex flex-col items-center justify-center h-full text-center p-8 bg-black relative overflow-hidden">
            {/* Background Effects */}
            <div className="absolute top-0 left-0 w-full h-full bg-[url('https://images.unsplash.com/photo-1542601906990-b4d3fb778b09?q=80&w=2574&auto=format&fit=crop')] bg-cover bg-center opacity-40 mix-blend-overlay"></div>
            <div className="absolute bottom-[-10%] right-[-10%] w-[80%] h-[50%] bg-[#00C853] rounded-full blur-[150px] opacity-20 animate-pulse-slow"></div>

            <div className="relative z-10 w-full max-w-md mx-auto">
                <div className="w-28 h-28 bg-white/10 backdrop-blur-xl rounded-[2rem] flex items-center justify-center mb-10 shadow-2xl border border-white/20 mx-auto animate-float">
                     <img src={appLogo} alt="KIN ECO-MAP Logo" className="w-full h-full object-contain p-4" />
                </div>

                <h1 className="text-5xl font-black mb-4 tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-white via-gray-200 to-gray-400">KIN ECO-MAP</h1>
                <p className="text-lg text-gray-300 mb-12 font-light max-w-xs mx-auto leading-relaxed">
                    Le futur de la propreté urbaine.<br/>
                    <span className="text-[#00C853] font-bold">Intelligent. Connecté. Vert.</span>
                </p>

                <div className="w-full space-y-4">
                    <button onClick={() => { setStep(2); setRegStep(1); }} className="w-full bg-[#00C853] hover:bg-[#00E676] text-black font-black py-4 rounded-2xl shadow-[0_0_20px_rgba(0,200,83,0.4)] transition-all flex items-center justify-center gap-2 transform active:scale-95 text-lg tracking-wide">
                        COMMENCER
                        <ChevronRight size={24} />
                    </button>

                    <button onClick={() => setShowLogin(true)} className="w-full bg-white/5 hover:bg-white/10 backdrop-blur-md border border-white/20 text-white font-bold py-4 rounded-2xl shadow-lg transition-all flex items-center justify-center gap-2 transform active:scale-95 tracking-wide">
                        SE CONNECTER
                        <LogIn size={20} />
                    </button>
                </div>

                {!isSupabaseConfigured() && (
                    <div className="mt-8 text-[10px] text-white/30 bg-white/5 px-4 py-1.5 rounded-full backdrop-blur-sm border border-white/5 inline-block">
                        Mode Démo (Local Storage)
                    </div>
                )}
            </div>
        </div>
    );

    const renderLogin = () => (
        <div className="flex flex-col h-full bg-[#F5F7FA] animate-fade-in relative">
            <div className="absolute top-0 right-0 w-full h-64 bg-gradient-to-b from-[#00C853]/10 to-transparent pointer-events-none"></div>

            {/* Header Login */}
            <div className="p-8 pb-4 relative z-10">
                <button onClick={() => setShowLogin(false)} className="p-3 -ml-3 hover:bg-gray-100 rounded-full transition-colors mb-6 text-gray-600">
                    <ArrowLeft size={28} />
                </button>

                <h2 className="text-4xl font-black text-gray-800 mb-2 tracking-tight">Bon retour.</h2>
                <p className="text-gray-500 font-medium">Connectez-vous pour continuer.</p>
            </div>

            {/* Role Tabs - Futuristic Pills */}
            <div className="px-8 py-4">
                <div className="bg-gray-200/50 p-1.5 rounded-2xl flex backdrop-blur-sm">
                    {[
                        { id: UserType.CITIZEN, label: 'Utilisateur' },
                        { id: UserType.COLLECTOR, label: 'Collecteur' },
                        { id: UserType.ADMIN, label: 'Admin' }
                    ].map(role => (
                        <button 
                            key={role.id}
                            onClick={() => setLoginRole(role.id as any)}
                            className={`flex-1 py-2.5 rounded-xl text-xs font-bold transition-all ${loginRole === role.id ? 'bg-white shadow-lg text-black transform scale-105' : 'text-gray-500 hover:text-gray-800'}`}
                        >
                            {role.label}
                        </button>
                    ))}
                </div>
            </div>

            {/* Form */}
            <div className="px-8 flex-1 space-y-6 overflow-y-auto">
                {loginError && (
                    <div className="bg-red-500/10 border border-red-500/20 text-red-500 p-4 rounded-2xl text-sm flex items-center gap-3 animate-shake">
                        <AlertCircle size={20} /> {loginError}
                    </div>
                )}

                <div className="space-y-4">
                    <div className="space-y-2">
                        <label className="text-sm font-bold text-gray-500 uppercase tracking-wider ml-1">
                            {loginRole === UserType.ADMIN ? 'Identifiant Admin' : 'Email ou Téléphone'}
                        </label>
                        <div className="relative group">
                            <div className="absolute left-4 top-4 text-gray-400 group-focus-within:text-[#00C853] transition-colors">
                                {loginRole === UserType.ADMIN ? <Shield size={20} /> : <UserIcon size={20} />}
                            </div>
                            <input 
                                type="text"
                                value={loginIdentifier}
                                onChange={(e) => setLoginIdentifier(e.target.value)}
                                placeholder={loginRole === UserType.ADMIN ? "admin@kinecomap.cd" : "Ex: +243 81..."}
                                className="w-full pl-12 pr-4 py-4 rounded-2xl border-2 border-transparent bg-white text-gray-900 focus:border-[#00C853] outline-none transition-all font-medium placeholder-gray-400 shadow-sm"
                            />
                        </div>
                    </div>

                    <div className="space-y-2">
                        <label className="text-sm font-bold text-gray-500 uppercase tracking-wider ml-1">Mot de passe</label>
                        <div className="relative group">
                            <div className="absolute left-4 top-4 text-gray-400 group-focus-within:text-[#00C853] transition-colors">
                                <Lock size={20} />
                            </div>
                            <input 
                                type={showPassword ? "text" : "password"}
                                value={loginPassword}
                                onChange={(e) => setLoginPassword(e.target.value)}
                                placeholder="••••••••"
                                className="w-full pl-12 pr-12 py-4 rounded-2xl border-2 border-transparent bg-white text-gray-900 focus:border-[#00C853] outline-none transition-all font-medium placeholder-gray-400 shadow-sm"
                            />
                            <button 
                                type="button"
                                onClick={() => setShowPassword(!showPassword)}
                                className="absolute right-4 top-4 text-gray-400 hover:text-gray-600"
                            >
                                {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                            </button>
                        </div>
                        <div className="flex justify-end">
                            <button onClick={() => { setShowForgotPass(true); setResetStep(1); }} className="text-xs text-[#00C853] font-bold hover:underline py-1">Mot de passe oublié ?</button>
                        </div>
                    </div>
                </div>

                <button 
                    onClick={handleLoginSubmit}
                    disabled={isLoggingIn || !loginIdentifier || !loginPassword}
                    className="w-full bg-[#00C853] hover:bg-[#00E676] disabled:bg-gray-300 disabled:cursor-not-allowed text-white font-black py-4 rounded-2xl shadow-[0_4px_14px_0_rgba(0,200,83,0.39)] transition-all flex items-center justify-center gap-3 transform active:scale-95 text-lg"
                >
                    {isLoggingIn ? <Loader2 className="animate-spin" /> : <>SE CONNECTER <ChevronRight size={24} /></>}
                </button>

                <div className="relative py-4">
                    <div className="absolute inset-0 flex items-center"><div className="w-full border-t border-gray-200"></div></div>
                    <div className="relative flex justify-center text-xs uppercase"><span className="bg-[#F5F7FA] px-2 text-gray-400 font-bold">Ou continuer avec</span></div>
                </div>

                <button className="w-full bg-white border border-gray-200 text-gray-700 font-bold py-4 rounded-2xl hover:bg-gray-50 transition-colors flex items-center justify-center gap-3 shadow-sm">
                    <Globe size={20} className="text-blue-500" /> Compte Google
                </button>
            </div>
        </div>
    );

    const renderForgotPassModal = () => (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setShowForgotPass(false)}></div>
            <div className="bg-white rounded-2xl w-full max-w-sm p-6 relative z-10 shadow-xl animate-fade-in-up">
                <button onClick={() => setShowForgotPass(false)} className="absolute top-4 right-4 text-gray-400 hover:text-gray-600">
                    <X size={20} />
                </button>
                <h3 className="text-xl font-bold text-gray-800 mb-2">
                    {resetStep === 1 ? 'Mot de passe oublié' : 'Réinitialisation'}
                </h3>

                {resetStep === 1 ? (
                    <>
                        <p className="text-sm text-gray-500 mb-6">Entrez votre identifiant pour recevoir un lien de réinitialisation.</p>
                        <form onSubmit={handleForgotPassRequest} className="space-y-4">
                            <input 
                                type="text" 
                                value={loginIdentifier}
                                onChange={(e) => setLoginIdentifier(e.target.value)}
                                placeholder="Email ou Téléphone"
                                className="w-full p-3 rounded-xl border border-gray-200 bg-gray-50 text-gray-800 outline-none focus:ring-2 focus:ring-[#00C853]"
                                required
                            />
                            <button type="submit" disabled={isLoggingIn} className="w-full py-3 bg-[#00C853] text-white rounded-xl font-bold">
                                {isLoggingIn ? <Loader2 className="animate-spin mx-auto" /> : 'Envoyer le code'}
                            </button>
                        </form>
                    </>
                ) : (
                    <>
                        <p className="text-sm text-gray-500 mb-6">Définissez votre nouveau mot de passe.</p>
                        <form onSubmit={handleResetConfirm} className="space-y-4">
                            <div>
                                <label className="text-xs font-bold text-gray-500 uppercase mb-1 block">Nouveau Mot de passe</label>
                                <input 
                                    type="password"
                                    value={newResetPassword}
                                    onChange={(e) => setNewResetPassword(e.target.value)}
                                    placeholder="••••••••"
                                    className="w-full p-3 rounded-xl border border-gray-200 bg-gray-50 text-gray-800 outline-none focus:ring-2 focus:ring-[#00C853]"
                                    required
                                />
                            </div>
                            <div>
                                <label className="text-xs font-bold text-gray-500 uppercase mb-1 block">Confirmer</label>
                                <input 
                                    type="password"
                                    value={confirmResetPassword}
                                    onChange={(e) => setConfirmResetPassword(e.target.value)}
                                    placeholder="••••••••"
                                    className="w-full p-3 rounded-xl border border-gray-200 bg-gray-50 text-gray-800 outline-none focus:ring-2 focus:ring-[#00C853]"
                                    required
                                />
                            </div>

                            {/* Optionnel: Champ Code si nécessaire */}
                            {/* <input type="text" placeholder="Code reçu par SMS/Email" ... /> */}

                            <button type="submit" disabled={isLoggingIn} className="w-full py-3 bg-[#00C853] text-white rounded-xl font-bold">
                                {isLoggingIn ? <Loader2 className="animate-spin mx-auto" /> : 'Modifier le mot de passe'}
                            </button>
                        </form>
                    </>
                )}
            </div>
        </div>
    );

    const renderRegisterStep1 = () => (
        <div className="space-y-6">
            <div>
                <h2 className="text-2xl font-black text-gray-800 mb-2">Créer un compte</h2>
                <p className="text-gray-500">Commençons par les bases.</p>
            </div>
            <div className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                    <input type="text" placeholder="Prénom" className="w-full p-4 rounded-2xl bg-white border-2 border-transparent focus:border-[#00C853] outline-none text-gray-800 font-medium" value={formData.firstName} onChange={(e) => updateData('firstName', e.target.value)} />
                    <input type="text" placeholder="Nom" className="w-full p-4 rounded-2xl bg-white border-2 border-transparent focus:border-[#00C853] outline-none text-gray-800 font-medium" value={formData.lastName} onChange={(e) => updateData('lastName', e.target.value)} />
                </div>
                <input type="tel" placeholder="Téléphone (+243...)" className="w-full p-4 rounded-2xl bg-white border-2 border-transparent focus:border-[#00C853] outline-none text-gray-800 font-medium" value={formData.phone} onChange={(e) => updateData('phone', e.target.value)} />
                <input type="email" placeholder="Email (Optionnel)" className="w-full p-4 rounded-2xl bg-white border-2 border-transparent focus:border-[#00C853] outline-none text-gray-800 font-medium" value={formData.email} onChange={(e) => updateData('email', e.target.value)} />
