            <div className="text-center text-sm text-gray-500">
                {otpTimer > 0 ? `Renvoyer dans ${otpTimer}s` : <button onClick={handleSendOTP} className="text-[#00C853] font-bold">Renvoyer le code</button>}
            </div>
            <button onClick={handleVerifyOTP} disabled={isVerifyingOTP} className="w-full py-4 bg-[#00C853] text-white rounded-2xl font-black text-lg shadow-lg flex items-center justify-center gap-2">
                {isVerifyingOTP ? <Loader2 className="animate-spin" /> : 'Vérifier'}
            </button>
        </div>
    );

    const renderRegisterStep3_Password = () => (
        <div className="space-y-6">
            <div>
                <h2 className="text-2xl font-black text-gray-800 mb-2">Sécurité</h2>
                <p className="text-gray-500">Choisissez un mot de passe fort.</p>
            </div>
            <div className="space-y-4">
                <input type="password" placeholder="Mot de passe" className="w-full p-4 rounded-2xl bg-white border-2 border-transparent focus:border-[#00C853] outline-none text-gray-800 font-medium" value={registerPassword} onChange={(e) => handlePasswordInput(e.target.value)} />

                {/* Password Strength Indicator */}
                <div className="flex gap-1 h-1.5 mt-2">
                    <div className={`flex-1 rounded-full ${passwordStrength >= 1 ? 'bg-red-500' : 'bg-gray-200'}`}></div>
                    <div className={`flex-1 rounded-full ${passwordStrength >= 2 ? 'bg-orange-500' : 'bg-gray-200'}`}></div>
                    <div className={`flex-1 rounded-full ${passwordStrength >= 3 ? 'bg-yellow-500' : 'bg-gray-200'}`}></div>
                    <div className={`flex-1 rounded-full ${passwordStrength >= 4 ? 'bg-green-500' : 'bg-gray-200'}`}></div>
                </div>

                <input type="password" placeholder="Confirmer mot de passe" className="w-full p-4 rounded-2xl bg-white border-2 border-transparent focus:border-[#00C853] outline-none text-gray-800 font-medium" value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)} />
            </div>
            <button onClick={() => setRegStep(4)} disabled={!registerPassword || registerPassword !== confirmPassword} className="w-full py-4 bg-[#00C853] text-white rounded-2xl font-black text-lg shadow-lg flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed">
                Suivant <ChevronRight />
            </button>
        </div>
    );

    const renderRegisterStep4_Role = () => (
        <div className="space-y-6">
            <div>
                <h2 className="text-2xl font-black text-gray-800 mb-2">Vous êtes ?</h2>
                <p className="text-gray-500">Sélectionnez votre type de profil.</p>
            </div>
            <div className="grid grid-cols-1 gap-4">
                {[
                    { id: UserType.CITIZEN, label: 'Citoyen / Ménage', icon: Home, desc: 'Gestion des déchets domestiques' },
                    { id: UserType.BUSINESS, label: 'Entreprise', icon: Building, desc: 'Solutions pour professionnels' },
                    { id: UserType.COLLECTOR, label: 'Collecteur', icon: Truck, desc: 'Je travaille dans la collecte' },
                ].map(type => (
                    <button 
                        key={type.id}
                        onClick={() => updateData('type', type.id)}
                        className={`p-6 rounded-3xl border-2 text-left transition-all ${formData.type === type.id ? 'border-[#00C853] bg-green-50' : 'border-transparent bg-white hover:border-gray-200'}`}
                    >
                        <div className="flex items-center gap-4">
                            <div className={`p-3 rounded-2xl ${formData.type === type.id ? 'bg-[#00C853] text-white' : 'bg-gray-100 text-gray-500'}`}>
                                <type.icon size={24} />
                            </div>
                            <div>
                                <h3 className="font-bold text-lg text-gray-800">{type.label}</h3>
                                <p className="text-sm text-gray-500">{type.desc}</p>
                            </div>
                        </div>
                    </button>
                ))}
            </div>
            <button onClick={() => setRegStep(5)} className="w-full py-4 bg-[#00C853] text-white rounded-2xl font-black text-lg shadow-lg flex items-center justify-center gap-2">
                Suivant <ChevronRight />
            </button>
        </div>
    );

    const renderRegisterStep5_Address = () => (
        <div className="space-y-6">
            <div>
                <h2 className="text-2xl font-black text-gray-800 mb-2">Localisation</h2>
                <p className="text-gray-500">Où devons-nous collecter ?</p>
            </div>
            <div className="space-y-4">
                <input type="text" placeholder="Adresse complète" className="w-full p-4 rounded-2xl bg-white border-2 border-transparent focus:border-[#00C853] outline-none text-gray-800 font-medium" value={formData.address} onChange={(e) => updateData('address', e.target.value)} />

                {/* Additional fields based on role */}
                {formData.type === UserType.BUSINESS && (
                    <>
                        <input type="text" placeholder="Nom de l'entreprise" className="w-full p-4 rounded-2xl bg-white border-2 border-transparent focus:border-[#00C853] outline-none text-gray-800 font-medium" value={formData.companyName} onChange={(e) => updateData('companyName', e.target.value)} />
                        <input type="text" placeholder="Secteur d'activité" className="w-full p-4 rounded-2xl bg-white border-2 border-transparent focus:border-[#00C853] outline-none text-gray-800 font-medium" value={formData.sector} onChange={(e) => updateData('sector', e.target.value)} />
                    </>
                )}

                {formData.type === UserType.CITIZEN && (
                    <select 
                        className="w-full p-4 rounded-2xl bg-white border-2 border-transparent focus:border-[#00C853] outline-none text-gray-800 font-medium"
                        value={formData.housingType}
                        onChange={(e) => updateData('housingType', e.target.value)}
                    >
                        <option value="Maison">Maison individuelle</option>
                        <option value="Appartement">Appartement</option>
                        <option value="Compound">Parcelle (Compound)</option>
                    </select>
                )}
            </div>
            <button onClick={() => setRegStep(6)} disabled={!formData.address} className="w-full py-4 bg-[#00C853] text-white rounded-2xl font-black text-lg shadow-lg flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed">
                Suivant <ChevronRight />
            </button>
        </div>
    );

    const renderRegisterStep6_Plan = () => {
        // Plans simulation
        const plans = [
            { id: 'standard', name: 'Standard', price: '10$', features: ['2x / semaine', 'Déchets ménagers'] },
            { id: 'plus', name: 'Plus', price: '15$', features: ['3x / semaine', 'Tri sélectif'], popular: true },
            { id: 'premium', name: 'Premium', price: '20$', features: ['Quotidien', 'Tout inclus'] },
        ];

        return (
            <div className="space-y-6">
                <div>
                    <h2 className="text-2xl font-black text-gray-800 mb-2">Abonnement</h2>
                    <p className="text-gray-500">Choisissez votre formule.</p>
                </div>
                <div className="space-y-3">
                    {plans.map(plan => (
                        <div 
                            key={plan.id}
                            onClick={() => updateData('subscription', plan.id)}
                            className={`p-5 rounded-3xl border-2 cursor-pointer transition-all relative ${formData.subscription === plan.id ? 'border-[#00C853] bg-green-50' : 'border-transparent bg-white hover:border-gray-200'}`}
                        >
                            {plan.popular && <span className="absolute top-0 right-0 bg-[#00C853] text-white text-xs font-bold px-3 py-1 rounded-bl-xl rounded-tr-xl">Populaire</span>}
                            <div className="flex justify-between items-center">
                                <div>
                                    <h3 className="font-bold text-gray-800">{plan.name}</h3>
                                    <p className="text-xs text-gray-500">{plan.features.join(' • ')}</p>
                                </div>
                                <div className="text-xl font-black text-[#2962FF]">{plan.price}</div>
                            </div>
                        </div>
                    ))}
                </div>

                <div className="flex items-center gap-3 py-2">
                    <div 
                        onClick={() => setAcceptedTerms(!acceptedTerms)}
                        className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center cursor-pointer transition-colors ${acceptedTerms ? 'bg-[#00C853] border-[#00C853] text-white' : 'border-gray-300'}`}
                    >
                        {acceptedTerms && <Check size={14} />}
                    </div>
                    <span className="text-xs text-gray-500">
                        J'accepte les <button onClick={() => setLegalModalType('terms')} className="text-[#2962FF] font-bold hover:underline">conditions d'utilisation</button> et la <button onClick={() => setLegalModalType('privacy')} className="text-[#2962FF] font-bold hover:underline">politique de confidentialité</button>.
                    </span>
                </div>

                <button onClick={handleRegisterSubmit} disabled={!acceptedTerms} className="w-full py-4 bg-[#00C853] text-white rounded-2xl font-black text-lg shadow-lg flex items-center justify-center gap-2 disabled:bg-gray-300 disabled:cursor-not-allowed">
                    {isLoggingIn ? <Loader2 className="animate-spin" /> : 'Créer mon compte'}
                </button>
            </div>
        );
    };

    if (showLogin) {
        return (
             <div className="h-screen bg-white flex flex-col md:items-center md:justify-center transition-colors duration-500">
                <div className="w-full h-full md:max-w-md md:h-[90vh] md:max-h-[850px] md:shadow-2xl md:rounded-[2.5rem] overflow-hidden relative flex flex-col bg-[#F5F7FA] border border-transparent">
                    {renderLogin()}
                </div>
                {showForgotPass && renderForgotPassModal()}
             </div>
        );
    }

    return (
        <div className="h-screen bg-white flex flex-col md:items-center md:justify-center transition-colors duration-500">
            <div className="w-full h-full md:max-w-md md:h-[90vh] md:max-h-[850px] md:shadow-2xl md:rounded-[2.5rem] overflow-hidden relative flex flex-col bg-[#F5F7FA] border border-transparent">
                {step > 1 && (
                    <div className="p-6 flex items-center shrink-0">
                        <button onClick={() => {
                            if (regStep > 1) setRegStep(prev => prev - 1);
                            else handleBack();
                        }} className="p-3 bg-white rounded-full hover:bg-gray-100 transition-colors shadow-sm">
                            <ArrowLeft size={20} className="text-gray-600" />
                        </button>
                        <div className="ml-4 flex-1 h-2 bg-gray-200 rounded-full overflow-hidden">
                            <div className="h-full bg-[#00C853] transition-all duration-500 ease-out shadow-[0_0_10px_#00C853]" style={{ width: `${((regStep) / 6) * 100}%` }}></div>
                        </div>
                    </div>
                )}

                <div className="flex-1 overflow-y-auto no-scrollbar p-6">
                    {step === 1 && renderWelcome()}
                    {step === 2 && (
                        <div className="animate-fade-in">
                            {/* Reusing existing logic but wrapped in a container for consistent spacing if needed */}
                            {regStep === 1 && renderRegisterStep1()}
                            {regStep === 2 && renderRegisterStep2_OTP()}
                            {regStep === 3 && renderRegisterStep3_Password()}
                            {regStep === 4 && renderRegisterStep4_Role()}
                            {regStep === 5 && renderRegisterStep5_Address()}
                            {regStep === 6 && renderRegisterStep6_Plan()}
                        </div>
                    )}
                </div>
            </div>

            <LegalDocs 
                isOpen={!!legalModalType} 
                type={legalModalType} 
                onClose={() => setLegalModalType(null)} 
            />
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { ChevronRight, ArrowLeft, Home, Building, Truck, Check, CreditCard, MapPin, LogIn, User as UserIcon, Shield, Lock, Phone, Eye, EyeOff, AlertCircle, Mail, Smartphone, RefreshCw, KeyRound, Globe, Loader2, X, Clock, Briefcase, GraduationCap } from 'lucide-react';
import { UserType, User } from '../types';
import { LegalDocs } from './LegalDocs';
import { UserAPI } from '../services/api';
import { isSupabaseConfigured } from '../services/supabaseClient';

interface OnboardingProps {
    onComplete: (user: Partial<User>) => void;
    appLogo?: string;
    onToast?: (msg: string, type: 'success' | 'error' | 'info') => void;
}

export const Onboarding: React.FC<OnboardingProps> = ({ onComplete, appLogo = './logo.png', onToast }) => {
    const [step, setStep] = useState(1);
    const [showLogin, setShowLogin] = useState(false);
    const [showForgotPass, setShowForgotPass] = useState(false);

    // Legal Docs State
    const [acceptedTerms, setAcceptedTerms] = useState(false);
    const [legalModalType, setLegalModalType] = useState<'terms' | 'privacy' | null>(null);

    // Login State
    const [loginRole, setLoginRole] = useState<UserType>(UserType.CITIZEN);
    const [loginIdentifier, setLoginIdentifier] = useState('');
    const [loginPassword, setLoginPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [isLoggingIn, setIsLoggingIn] = useState(false);
    const [loginError, setLoginError] = useState<string | null>(null);
    const [currentTime, setCurrentTime] = useState(new Date());

    // Forgot Password State
    const [resetStep, setResetStep] = useState<1 | 2>(1); // 1: Email, 2: New Password
    const [resetCode, setResetCode] = useState(''); // Code de vérification
    const [newResetPassword, setNewResetPassword] = useState('');
    const [confirmResetPassword, setConfirmResetPassword] = useState('');

    // Register State
    const [regStep, setRegStep] = useState(1);
    const [otpCode, setOtpCode] = useState(['', '', '', '', '', '']);
    const [isVerifyingOTP, setIsVerifyingOTP] = useState(false);
    const [otpTimer, setOtpTimer] = useState(0);

    const [registerPassword, setRegisterPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [passwordStrength, setPasswordStrength] = useState(0); 

    const [formData, setFormData] = useState<Partial<User>>({
        firstName: '',
        lastName: '',
        phone: '',
        email: '',
        type: UserType.CITIZEN,
        address: '',
        subscription: 'plus',
        companyName: '',
        companyPhone: '',
        sector: '',
        vehicleType: '',
        housingType: 'Maison'
    });

    // Clock Timer
    useEffect(() => {
        const timer = setInterval(() => setCurrentTime(new Date()), 1000);
        return () => clearInterval(timer);
    }, []);

    // --- Helpers (omitted for brevity, same logic) ---
    const handleNext = () => setStep(prev => prev + 1);
    const handleBack = () => setStep(prev => prev - 1);
    const updateData = (key: string, value: any) => setFormData(prev => ({ ...prev, [key]: value }));
    const calculatePasswordStrength = (pass: string) => {
        let strength = 0;
        if (pass.length >= 8) strength++;
        if (/[A-Z]/.test(pass)) strength++;
        if (/[0-9]/.test(pass)) strength++;
        if (/[0-9]/.test(pass)) strength++;
        if (/[^A-Za-z0-9]/.test(pass)) strength++;
        setPasswordStrength(strength);
    };
    const handlePasswordInput = (val: string) => {
        setRegisterPassword(val);
        calculatePasswordStrength(val);
    };

    // --- OTP Logic ---
    const startOtpTimer = () => {
        setOtpTimer(60);
        const interval = setInterval(() => {
            setOtpTimer((prev) => {
                if (prev <= 1) {
                    clearInterval(interval);
                    return 0;
                }
                return prev - 1;
            });
        }, 1000);
    };

    const handleSendOTP = async () => {
        if (!formData.firstName || !formData.lastName || !formData.phone) {
            if(onToast) onToast("Veuillez remplir tous les champs obligatoires", "error");
            return;
        }
        setIsVerifyingOTP(true);
        setTimeout(() => {
            setIsVerifyingOTP(false);
            setRegStep(2);
            startOtpTimer();
            if(onToast) onToast(`Code envoyé au ${formData.phone}`, "info");
        }, 1500);
    };

    const handleVerifyOTP = async () => {
        const code = otpCode.join('');
        if (code.length !== 6) {
            if(onToast) onToast("Code incomplet", "error");
            return;
        }
        setIsVerifyingOTP(true);
        const isValid = await UserAPI.verifyOTP(code);
        setIsVerifyingOTP(false);
        if (isValid) {
            if(onToast) onToast("Numéro vérifié avec succès", "success");
            setRegStep(3);
        } else {
            if(onToast) onToast("Code incorrect (Essayez 123456)", "error");
            setOtpCode(['', '', '', '', '', '']);
        }
    };

    const handleOtpChange = (index: number, value: string) => {
        if (isNaN(Number(value))) return;
        const newOtp = [...otpCode];
        newOtp[index] = value;
        setOtpCode(newOtp);
        if (value && index < 5) {
            const nextInput = document.getElementById(`otp-${index + 1}`);
            nextInput?.focus();
        }
    };

    // --- Login Logic ---
    const handleLoginSubmit = async () => {
        if (!loginIdentifier || !loginPassword) {
            setLoginError("Veuillez remplir tous les champs");
            return;
        }
        setIsLoggingIn(true);
        setLoginError(null);
        try {
            const user = await UserAPI.login(loginIdentifier, loginPassword);
            if (user) {
                if(onToast) onToast(`Bon retour, ${user.firstName} !`, "success");
                onComplete(user);
            } else {
                setLoginError("Identifiants incorrects ou utilisateur introuvable.");
                if(onToast) onToast("Échec de connexion", "error");
            }
        } catch (err) {
            console.error(err);
            setLoginError("Une erreur de connexion est survenue.");
        } finally {
            setIsLoggingIn(false);
        }
    };

    // --- Forgot Password Logic ---
    const handleForgotPassRequest = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!loginIdentifier) {
            if(onToast) onToast("Veuillez saisir votre identifiant", "error");
            return;
        }
        setIsLoggingIn(true);
        try {
            await UserAPI.resetPassword(loginIdentifier);
            setResetStep(2);
            if(onToast) onToast("Code de réinitialisation envoyé.", "success");
        } catch (e) {
            if(onToast) onToast("Erreur lors de la demande.", "error");
        } finally {
            setIsLoggingIn(false);
        }
    };

    const handleResetConfirm = async (e: React.FormEvent) => {
        e.preventDefault();
        if (newResetPassword !== confirmResetPassword) {
            if(onToast) onToast("Les mots de passe ne correspondent pas", "error");
            return;
        }
        if (newResetPassword.length < 6) {
            if(onToast) onToast("Mot de passe trop court", "error");
            return;
        }

        setIsLoggingIn(true);
        try {
            // Simulation API Call
            await UserAPI.confirmPasswordReset(loginIdentifier, newResetPassword);
            setShowForgotPass(false);
            setResetStep(1);
            setLoginPassword('');
            if(onToast) onToast("Mot de passe modifié avec succès. Connectez-vous.", "success");
        } catch (e) {
            if(onToast) onToast("Erreur lors de la modification.", "error");
        } finally {
            setIsLoggingIn(false);
        }
    };

    // --- Register Submit ---
    const handleRegisterSubmit = async () => {
        try {
            const newUser: User = {
                id: '',
                firstName: formData.firstName || '',
                lastName: formData.lastName || '',
                email: formData.email,
                phone: formData.phone || '',
                type: formData.type || UserType.CITIZEN,
                address: formData.address || '',
                points: 100,
                collections: 0,
                badges: 0,
                subscription: formData.subscription || 'standard',
                companyName: formData.companyName,
                sector: formData.sector,
                housingType: formData.housingType
            };
            await UserAPI.register(newUser, registerPassword);
            if(onToast) onToast("Compte créé avec succès !", "success");
            onComplete(newUser);
        } catch (error) {
            console.error("Registration failed", error);
            if(onToast) onToast("Erreur lors de la création du compte.", "error");
        }
    };

    // --- RENDER FUNCTIONS ---

    const renderWelcome = () => (
        <div className="flex flex-col items-center justify-center h-full text-center p-8 bg-black relative overflow-hidden">
            {/* Background Effects */}
            <div className="absolute top-0 left-0 w-full h-full bg-[url('https://images.unsplash.com/photo-1542601906990-b4d3fb778b09?q=80&w=2574&auto=format&fit=crop')] bg-cover bg-center opacity-40 mix-blend-overlay"></div>
            <div className="absolute bottom-[-10%] right-[-10%] w-[80%] h-[50%] bg-[#00C853] rounded-full blur-[150px] opacity-20 animate-pulse-slow"></div>

            <div className="relative z-10 w-full max-w-md mx-auto">
                <div className="w-28 h-28 bg-white/10 backdrop-blur-xl rounded-[2rem] flex items-center justify-center mb-10 shadow-2xl border border-white/20 mx-auto animate-float">
                     <img src={appLogo} alt="KIN ECO-MAP Logo" className="w-full h-full object-contain p-4" />
                </div>

                <h1 className="text-5xl font-black mb-4 tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-white via-gray-200 to-gray-400">KIN ECO-MAP</h1>
                <p className="text-lg text-gray-300 mb-12 font-light max-w-xs mx-auto leading-relaxed">
                    Le futur de la propreté urbaine.<br/>
                    <span className="text-[#00C853] font-bold">Intelligent. Connecté. Vert.</span>
                </p>

                <div className="w-full space-y-4">
                    <button onClick={() => { setStep(2); setRegStep(1); }} className="w-full bg-[#00C853] hover:bg-[#00E676] text-black font-black py-4 rounded-2xl shadow-[0_0_20px_rgba(0,200,83,0.4)] transition-all flex items-center justify-center gap-2 transform active:scale-95 text-lg tracking-wide">
                        COMMENCER
                        <ChevronRight size={24} />
                    </button>

                    <button onClick={() => setShowLogin(true)} className="w-full bg-white/5 hover:bg-white/10 backdrop-blur-md border border-white/20 text-white font-bold py-4 rounded-2xl shadow-lg transition-all flex items-center justify-center gap-2 transform active:scale-95 tracking-wide">
                        SE CONNECTER
                        <LogIn size={20} />
                    </button>
                </div>

                {!isSupabaseConfigured() && (
                    <div className="mt-8 text-[10px] text-white/30 bg-white/5 px-4 py-1.5 rounded-full backdrop-blur-sm border border-white/5 inline-block">
                        Mode Démo (Local Storage)
                    </div>
                )}
            </div>
        </div>
    );

    const renderLogin = () => {
        const formattedDate = currentTime.toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });
        const capitalize = (s: string) => s.charAt(0).toUpperCase() + s.slice(1);
        const displayDate = formattedDate.split(' ').map(capitalize).join(' ');
        const displayTime = currentTime.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit', second: '2-digit' });

        // Map roles to "Futuriss" style
        const roleConfig = [
            { id: UserType.ADMIN, label: 'Administratif' },
            { id: UserType.COLLECTOR, label: 'Collecteur' },
            { id: UserType.CITIZEN, label: 'Citoyen' },
            { id: UserType.BUSINESS, label: 'Entreprise' }
        ];

        return (
            <div className="flex items-center justify-center min-h-screen bg-[#0f172a] relative overflow-hidden font-sans">
                {/* Background Pattern */}
                <div className="absolute inset-0 opacity-10" style={{
                    backgroundImage: 'radial-gradient(#ffffff 1px, transparent 1px)',
                    backgroundSize: '30px 30px'
                }}></div>
                <div className="absolute bottom-[-20%] left-[-10%] w-[600px] h-[600px] bg-white/5 rounded-full blur-[100px]"></div>

                {/* Login Card */}
                <div className="relative w-full max-w-md mx-4 bg-[#1e293b]/90 backdrop-blur-md rounded-[2rem] border border-white/10 shadow-2xl overflow-hidden flex flex-col">

                    {/* Header Blue Section */}
                    <div className="bg-gradient-to-b from-[#1e3a8a] to-[#1e293b] p-8 text-center relative">
                        <div className="mb-2 flex justify-center">
                            <span className="text-red-500 font-bold italic tracking-widest text-xs">KIN ECO</span>
                        </div>
                        <h2 className="text-2xl font-black text-white mb-4 tracking-wide uppercase">KIN ECO-MAP</h2>
                        <div className="flex justify-center gap-3">
                            <span className="bg-white/10 backdrop-blur-sm px-3 py-1 rounded-full text-[10px] text-white flex items-center gap-1 border border-white/10">
                                <Shield size={10} /> Sécurisé
                            </span>
