            <button onClick={() => setRegStep(4)} disabled={!registerPassword || registerPassword !== confirmPassword} className="w-full py-4 bg-[#00C853] text-white rounded-2xl font-black text-lg shadow-lg flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed">
                Suivant <ChevronRight />
            </button>
        </div>
    );

    const renderRegisterStep4_Role = () => (
        <div className="space-y-6">
            <div>
                <h2 className="text-2xl font-black text-gray-800 mb-2">Vous êtes ?</h2>
                <p className="text-gray-500">Sélectionnez votre type de profil.</p>
            </div>
            <div className="grid grid-cols-1 gap-4">
                {[
                    { id: UserType.CITIZEN, label: 'Citoyen / Ménage', icon: Home, desc: 'Gestion des déchets domestiques' },
                    { id: UserType.BUSINESS, label: 'Entreprise', icon: Building, desc: 'Solutions pour professionnels' },
                    { id: UserType.COLLECTOR, label: 'Collecteur', icon: Truck, desc: 'Je travaille dans la collecte' },
                ].map(type => (
                    <button 
                        key={type.id}
                        onClick={() => updateData('type', type.id)}
                        className={`p-6 rounded-3xl border-2 text-left transition-all ${formData.type === type.id ? 'border-[#00C853] bg-green-50' : 'border-transparent bg-white hover:border-gray-200'}`}
                    >
                        <div className="flex items-center gap-4">
                            <div className={`p-3 rounded-2xl ${formData.type === type.id ? 'bg-[#00C853] text-white' : 'bg-gray-100 text-gray-500'}`}>
                                <type.icon size={24} />
                            </div>
                            <div>
                                <h3 className="font-bold text-lg text-gray-800">{type.label}</h3>
                                <p className="text-sm text-gray-500">{type.desc}</p>
                            </div>
                        </div>
                    </button>
                ))}
            </div>
            <button onClick={() => setRegStep(5)} className="w-full py-4 bg-[#00C853] text-white rounded-2xl font-black text-lg shadow-lg flex items-center justify-center gap-2">
                Suivant <ChevronRight />
            </button>
        </div>
    );

    const renderRegisterStep5_Address = () => (
        <div className="space-y-6">
            <div>
                <h2 className="text-2xl font-black text-gray-800 mb-2">Localisation</h2>
                <p className="text-gray-500">Où devons-nous collecter ?</p>
            </div>
            <div className="space-y-4">
                <input type="text" placeholder="Adresse complète" className="w-full p-4 rounded-2xl bg-white border-2 border-transparent focus:border-[#00C853] outline-none text-gray-800 font-medium" value={formData.address} onChange={(e) => updateData('address', e.target.value)} />

                {/* Additional fields based on role */}
                {formData.type === UserType.BUSINESS && (
                    <>
                        <input type="text" placeholder="Nom de l'entreprise" className="w-full p-4 rounded-2xl bg-white border-2 border-transparent focus:border-[#00C853] outline-none text-gray-800 font-medium" value={formData.companyName} onChange={(e) => updateData('companyName', e.target.value)} />
                        <input type="text" placeholder="Secteur d'activité" className="w-full p-4 rounded-2xl bg-white border-2 border-transparent focus:border-[#00C853] outline-none text-gray-800 font-medium" value={formData.sector} onChange={(e) => updateData('sector', e.target.value)} />
                    </>
                )}

                {formData.type === UserType.CITIZEN && (
                    <select 
                        className="w-full p-4 rounded-2xl bg-white border-2 border-transparent focus:border-[#00C853] outline-none text-gray-800 font-medium"
                        value={formData.housingType}
                        onChange={(e) => updateData('housingType', e.target.value)}
                    >
                        <option value="Maison">Maison individuelle</option>
                        <option value="Appartement">Appartement</option>
                        <option value="Compound">Parcelle (Compound)</option>
                    </select>
                )}
            </div>
            <button onClick={() => setRegStep(6)} disabled={!formData.address} className="w-full py-4 bg-[#00C853] text-white rounded-2xl font-black text-lg shadow-lg flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed">
                Suivant <ChevronRight />
            </button>
        </div>
    );

    const renderRegisterStep6_Plan = () => {
        // Plans simulation
        const plans = [
            { id: 'standard', name: 'Standard', price: '10$', features: ['2x / semaine', 'Déchets ménagers'] },
            { id: 'plus', name: 'Plus', price: '15$', features: ['3x / semaine', 'Tri sélectif'], popular: true },
            { id: 'premium', name: 'Premium', price: '20$', features: ['Quotidien', 'Tout inclus'] },
        ];

        return (
            <div className="space-y-6">
                <div>
                    <h2 className="text-2xl font-black text-gray-800 mb-2">Abonnement</h2>
                    <p className="text-gray-500">Choisissez votre formule.</p>
                </div>
                <div className="space-y-3">
                    {plans.map(plan => (
                        <div 
                            key={plan.id}
                            onClick={() => updateData('subscription', plan.id)}
                            className={`p-5 rounded-3xl border-2 cursor-pointer transition-all relative ${formData.subscription === plan.id ? 'border-[#00C853] bg-green-50' : 'border-transparent bg-white hover:border-gray-200'}`}
                        >
                            {plan.popular && <span className="absolute top-0 right-0 bg-[#00C853] text-white text-xs font-bold px-3 py-1 rounded-bl-xl rounded-tr-xl">Populaire</span>}
                            <div className="flex justify-between items-center">
                                <div>
                                    <h3 className="font-bold text-gray-800">{plan.name}</h3>
                                    <p className="text-xs text-gray-500">{plan.features.join(' • ')}</p>
                                </div>
                                <div className="text-xl font-black text-[#2962FF]">{plan.price}</div>
                            </div>
                        </div>
                    ))}
                </div>

                <div className="flex items-center gap-3 py-2">
                    <div 
                        onClick={() => setAcceptedTerms(!acceptedTerms)}
                        className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center cursor-pointer transition-colors ${acceptedTerms ? 'bg-[#00C853] border-[#00C853] text-white' : 'border-gray-300'}`}
                    >
                        {acceptedTerms && <Check size={14} />}
                    </div>
                    <span className="text-xs text-gray-500">
                        J'accepte les <button onClick={() => setLegalModalType('terms')} className="text-[#2962FF] font-bold hover:underline">conditions d'utilisation</button> et la <button onClick={() => setLegalModalType('privacy')} className="text-[#2962FF] font-bold hover:underline">politique de confidentialité</button>.
                    </span>
                </div>

                <button onClick={handleRegisterSubmit} disabled={!acceptedTerms} className="w-full py-4 bg-[#00C853] text-white rounded-2xl font-black text-lg shadow-lg flex items-center justify-center gap-2 disabled:bg-gray-300 disabled:cursor-not-allowed">
                    {isLoggingIn ? <Loader2 className="animate-spin" /> : 'Créer mon compte'}
                </button>
            </div>
        );
    };

    if (showLogin) {
        return renderLogin();
    }

    return (
        <div className="h-screen bg-white flex flex-col md:items-center md:justify-center transition-colors duration-500">
            <div className="w-full h-full md:max-w-md md:h-[90vh] md:max-h-[850px] md:shadow-2xl md:rounded-[2.5rem] overflow-hidden relative flex flex-col bg-[#F5F7FA] border border-transparent">
                {step > 1 && (
                    <div className="p-6 flex items-center shrink-0">
                        <button onClick={() => {
                            if (regStep > 1) setRegStep(prev => prev - 1);
                            else handleBack();
                        }} className="p-3 bg-white rounded-full hover:bg-gray-100 transition-colors shadow-sm">
                            <ArrowLeft size={20} className="text-gray-600" />
                        </button>
                        <div className="ml-4 flex-1 h-2 bg-gray-200 rounded-full overflow-hidden">
                            <div className="h-full bg-[#00C853] transition-all duration-500 ease-out shadow-[0_0_10px_#00C853]" style={{ width: `${((regStep) / 6) * 100}%` }}></div>
                        </div>
                    </div>
                )}

                <div className="flex-1 overflow-y-auto no-scrollbar p-6">
                    {step === 1 && renderWelcome()}
                    {step === 2 && (
                        <div className="animate-fade-in">
                            {/* Reusing existing logic but wrapped in a container for consistent spacing if needed */}
                            {regStep === 1 && renderRegisterStep1()}
                            {regStep === 2 && renderRegisterStep2_OTP()}
                            {regStep === 3 && renderRegisterStep3_Password()}
                            {regStep === 4 && renderRegisterStep4_Role()}
                            {regStep === 5 && renderRegisterStep5_Address()}
                            {regStep === 6 && renderRegisterStep6_Plan()}
                        </div>
                    )}
                </div>
            </div>

            <LegalDocs 
                isOpen={!!legalModalType} 
                type={legalModalType} 
                onClose={() => setLegalModalType(null)} 
            />
            {showForgotPass && renderForgotPassModal()}
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { ChevronRight, ArrowLeft, Home, Building, Truck, Check, CreditCard, MapPin, LogIn, User as UserIcon, Shield, Lock, Phone, Eye, EyeOff, AlertCircle, Mail, Smartphone, RefreshCw, KeyRound, Globe, Loader2, X, Clock, Briefcase, GraduationCap, ShieldCheck } from 'lucide-react';
import { UserType, User } from '../types';
import { LegalDocs } from './LegalDocs';
import { UserAPI } from '../services/api';
import { isSupabaseConfigured } from '../services/supabaseClient';

interface OnboardingProps {
    onComplete: (user: Partial<User>) => void;
    appLogo?: string;
    onToast?: (msg: string, type: 'success' | 'error' | 'info') => void;
}

export const Onboarding: React.FC<OnboardingProps> = ({ onComplete, appLogo = './logo.png', onToast }) => {
    const [step, setStep] = useState(1);
    const [showLogin, setShowLogin] = useState(false);
    const [showForgotPass, setShowForgotPass] = useState(false);

    // Legal Docs State
    const [acceptedTerms, setAcceptedTerms] = useState(false);
    const [legalModalType, setLegalModalType] = useState<'terms' | 'privacy' | null>(null);

    // Login State
    const [loginRole, setLoginRole] = useState<UserType>(UserType.CITIZEN);
    const [loginIdentifier, setLoginIdentifier] = useState('');
    const [loginPassword, setLoginPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [isLoggingIn, setIsLoggingIn] = useState(false);
    const [loginError, setLoginError] = useState<string | null>(null);
    const [currentTime, setCurrentTime] = useState(new Date());

    // Forgot Password State
    const [resetStep, setResetStep] = useState<1 | 2>(1); // 1: Email, 2: New Password
    const [resetCode, setResetCode] = useState(''); // Code de vérification
    const [newResetPassword, setNewResetPassword] = useState('');
    const [confirmResetPassword, setConfirmResetPassword] = useState('');

    // Register State
    const [regStep, setRegStep] = useState(1);
    const [otpCode, setOtpCode] = useState(['', '', '', '', '', '']);
    const [isVerifyingOTP, setIsVerifyingOTP] = useState(false);
    const [otpTimer, setOtpTimer] = useState(0);

    const [registerPassword, setRegisterPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [passwordStrength, setPasswordStrength] = useState(0); 

    const [formData, setFormData] = useState<Partial<User>>({
        firstName: '',
        lastName: '',
        phone: '',
        email: '',
        type: UserType.CITIZEN,
        address: '',
        subscription: 'plus',
        companyName: '',
        companyPhone: '',
        sector: '',
        vehicleType: '',
        housingType: 'Maison'
    });

    // Clock Timer
    useEffect(() => {
        const timer = setInterval(() => setCurrentTime(new Date()), 1000);
        return () => clearInterval(timer);
    }, []);

    // --- Helpers (omitted for brevity, same logic) ---
    const handleNext = () => setStep(prev => prev + 1);
    const handleBack = () => setStep(prev => prev - 1);
    const updateData = (key: string, value: any) => setFormData(prev => ({ ...prev, [key]: value }));
    const calculatePasswordStrength = (pass: string) => {
        let strength = 0;
        if (pass.length >= 8) strength++;
        if (/[A-Z]/.test(pass)) strength++;
        if (/[0-9]/.test(pass)) strength++;
        if (/[0-9]/.test(pass)) strength++;
        if (/[^A-Za-z0-9]/.test(pass)) strength++;
        setPasswordStrength(strength);
    };
    const handlePasswordInput = (val: string) => {
        setRegisterPassword(val);
        calculatePasswordStrength(val);
    };

    // --- OTP Logic ---
    const startOtpTimer = () => {
        setOtpTimer(60);
        const interval = setInterval(() => {
            setOtpTimer((prev) => {
                if (prev <= 1) {
                    clearInterval(interval);
                    return 0;
                }
                return prev - 1;
            });
        }, 1000);
    };

    const handleSendOTP = async () => {
        if (!formData.firstName || !formData.lastName || !formData.phone) {
            if(onToast) onToast("Veuillez remplir tous les champs obligatoires", "error");
            return;
        }
        setIsVerifyingOTP(true);
        setTimeout(() => {
            setIsVerifyingOTP(false);
            setRegStep(2);
            startOtpTimer();
            if(onToast) onToast(`Code envoyé au ${formData.phone}`, "info");
        }, 1500);
    };

    const handleVerifyOTP = async () => {
        const code = otpCode.join('');
        if (code.length !== 6) {
            if(onToast) onToast("Code incomplet", "error");
            return;
        }
        setIsVerifyingOTP(true);
        const isValid = await UserAPI.verifyOTP(code);
        setIsVerifyingOTP(false);
        if (isValid) {
            if(onToast) onToast("Numéro vérifié avec succès", "success");
            setRegStep(3);
        } else {
            if(onToast) onToast("Code incorrect (Essayez 123456)", "error");
            setOtpCode(['', '', '', '', '', '']);
        }
    };

    const handleOtpChange = (index: number, value: string) => {
        if (isNaN(Number(value))) return;
        const newOtp = [...otpCode];
        newOtp[index] = value;
        setOtpCode(newOtp);
        if (value && index < 5) {
            const nextInput = document.getElementById(`otp-${index + 1}`);
            nextInput?.focus();
        }
    };

    // --- Login Logic ---
    const handleLoginSubmit = async () => {
        if (!loginIdentifier || !loginPassword) {
            setLoginError("Veuillez remplir tous les champs");
            return;
        }
        setIsLoggingIn(true);
        setLoginError(null);
        try {
            const user = await UserAPI.login(loginIdentifier, loginPassword);
            if (user) {
                if(onToast) onToast(`Bon retour, ${user.firstName} !`, "success");
                onComplete(user);
            } else {
                setLoginError("Identifiants incorrects ou utilisateur introuvable.");
                if(onToast) onToast("Échec de connexion", "error");
            }
        } catch (err) {
            console.error(err);
            setLoginError("Une erreur de connexion est survenue.");
        } finally {
            setIsLoggingIn(false);
        }
    };

    // --- Forgot Password Logic ---
    const handleForgotPassRequest = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!loginIdentifier) {
            if(onToast) onToast("Veuillez saisir votre identifiant", "error");
            return;
        }
        setIsLoggingIn(true);
        try {
            await UserAPI.resetPassword(loginIdentifier);
            setResetStep(2);
            if(onToast) onToast("Code de réinitialisation envoyé.", "success");
        } catch (e) {
            if(onToast) onToast("Erreur lors de la demande.", "error");
        } finally {
            setIsLoggingIn(false);
        }
    };

    const handleResetConfirm = async (e: React.FormEvent) => {
        e.preventDefault();
        if (newResetPassword !== confirmResetPassword) {
            if(onToast) onToast("Les mots de passe ne correspondent pas", "error");
            return;
        }
        if (newResetPassword.length < 6) {
            if(onToast) onToast("Mot de passe trop court", "error");
            return;
        }

        setIsLoggingIn(true);
        try {
            // Simulation API Call
            await UserAPI.confirmPasswordReset(loginIdentifier, newResetPassword);
            setShowForgotPass(false);
            setResetStep(1);
            setLoginPassword('');
            if(onToast) onToast("Mot de passe modifié avec succès. Connectez-vous.", "success");
        } catch (e) {
            if(onToast) onToast("Erreur lors de la modification.", "error");
        } finally {
            setIsLoggingIn(false);
        }
    };

    // --- Register Submit ---
    const handleRegisterSubmit = async () => {
        try {
            const newUser: User = {
                id: '',
                firstName: formData.firstName || '',
                lastName: formData.lastName || '',
                email: formData.email,
                phone: formData.phone || '',
                type: formData.type || UserType.CITIZEN,
                address: formData.address || '',
                points: 100,
                collections: 0,
                badges: 0,
                subscription: formData.subscription || 'standard',
                companyName: formData.companyName,
                sector: formData.sector,
                housingType: formData.housingType
            };
            await UserAPI.register(newUser, registerPassword);
            if(onToast) onToast("Compte créé avec succès !", "success");
            onComplete(newUser);
        } catch (error) {
            console.error("Registration failed", error);
            if(onToast) onToast("Erreur lors de la création du compte.", "error");
        }
    };

    // --- RENDER FUNCTIONS ---

    const renderWelcome = () => (
        <div className="flex flex-col items-center justify-center h-full text-center p-8 bg-black relative overflow-hidden">
            {/* Background Effects */}
            <div className="absolute top-0 left-0 w-full h-full bg-[url('https://images.unsplash.com/photo-1542601906990-b4d3fb778b09?q=80&w=2574&auto=format&fit=crop')] bg-cover bg-center opacity-40 mix-blend-overlay"></div>
            <div className="absolute bottom-[-10%] right-[-10%] w-[80%] h-[50%] bg-[#00C853] rounded-full blur-[150px] opacity-20 animate-pulse-slow"></div>

            <div className="relative z-10 w-full max-w-md mx-auto">
                <div className="w-28 h-28 bg-white/10 backdrop-blur-xl rounded-[2rem] flex items-center justify-center mb-10 shadow-2xl border border-white/20 mx-auto animate-float">
                     <img src={appLogo} alt="KIN ECO-MAP Logo" className="w-full h-full object-contain p-4" />
                </div>

                <h1 className="text-5xl font-black mb-4 tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-white via-gray-200 to-gray-400">KIN ECO-MAP</h1>
                <p className="text-lg text-gray-300 mb-12 font-light max-w-xs mx-auto leading-relaxed">
                    Le futur de la propreté urbaine.<br/>
                    <span className="text-[#00C853] font-bold">Intelligent. Connecté. Vert.</span>
                </p>

                <div className="w-full space-y-4">
                    <button onClick={() => { setStep(2); setRegStep(1); }} className="w-full bg-[#00C853] hover:bg-[#00E676] text-black font-black py-4 rounded-2xl shadow-[0_0_20px_rgba(0,200,83,0.4)] transition-all flex items-center justify-center gap-2 transform active:scale-95 text-lg tracking-wide">
                        COMMENCER
                        <ChevronRight size={24} />
                    </button>

                    <button onClick={() => setShowLogin(true)} className="w-full bg-white/5 hover:bg-white/10 backdrop-blur-md border border-white/20 text-white font-bold py-4 rounded-2xl shadow-lg transition-all flex items-center justify-center gap-2 transform active:scale-95 tracking-wide">
                        SE CONNECTER
                        <LogIn size={20} />
                    </button>
                </div>

                {!isSupabaseConfigured() && (
                    <div className="mt-8 text-[10px] text-white/30 bg-white/5 px-4 py-1.5 rounded-full backdrop-blur-sm border border-white/5 inline-block">
                        Mode Démo (Local Storage)
                    </div>
                )}
            </div>
        </div>
    );

    const renderLogin = () => {
        const formattedDate = currentTime.toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });
        const capitalize = (s: string) => s.charAt(0).toUpperCase() + s.slice(1);
        const displayDate = formattedDate.split(' ').map(capitalize).join(' ');
        const displayTime = currentTime.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit', second: '2-digit' });

        // Map roles to "Futuriss" style labels as requested
        const roleConfig = [
            { id: UserType.ADMIN, label: 'Administratif' },
            { id: UserType.COLLECTOR, label: 'Collecteur' },
            { id: UserType.CITIZEN, label: 'Citoyen' },
            { id: UserType.BUSINESS, label: 'Entreprise' }
        ];

        return (
            <div className="flex items-center justify-center min-h-screen bg-[#F5F7FA] relative overflow-hidden font-sans text-gray-800">
                {/* Background Blobs */}
                <div className="absolute top-[-10%] right-[-10%] w-[500px] h-[500px] bg-[#00C853]/10 rounded-full blur-[100px] pointer-events-none"></div>
                <div className="absolute bottom-[-10%] left-[-10%] w-[500px] h-[500px] bg-[#2962FF]/10 rounded-full blur-[100px] pointer-events-none"></div>

                {/* Login Card */}
                <div className="relative w-full max-w-md mx-4 bg-white/80 backdrop-blur-xl rounded-[2.5rem] border border-white/60 shadow-2xl overflow-hidden flex flex-col">

                    {/* 1. En-tête avec Badges */}
                    <div className="p-8 pb-2 text-center relative">
                        <div className="mb-2 flex justify-center">
                            <span className="text-[#00C853] font-black italic tracking-widest text-[10px] bg-green-50 px-3 py-1 rounded-full border border-green-100">KIN ECO</span>
                        </div>
                        <h2 className="text-3xl font-black text-gray-800 mb-4 tracking-tighter uppercase">KIN ECO-MAP</h2>
                        <div className="flex justify-center gap-3">
                            <span className="bg-gray-100 px-3 py-1 rounded-full text-[10px] text-gray-600 flex items-center gap-1 border border-gray-200 font-bold tracking-wide">
                                <ShieldCheck size={12} className="text-[#00C853]" /> Sécurisé
                            </span>
                            <span className="bg-gray-100 px-3 py-1 rounded-full text-[10px] text-gray-600 flex items-center gap-1 border border-gray-200 font-bold tracking-wide">
                                <Globe size={12} className="text-[#2962FF]" /> Écologie
                            </span>
                        </div>
                    </div>

                    {/* Content Section */}
                    <div className="p-8 pt-4 flex flex-col space-y-6">

                        {/* 2. Message d'accueil & Titre */}
                        <div className="text-center space-y-1">
                            <h1 className="text-xl font-bold text-gray-700 tracking-wide uppercase">SE CONNECTER</h1>
                            <p className="text-[#00C853] font-bold text-sm tracking-wide">Bonjour, bienvenue</p>
                        </div>

                        {/* Widget Date */}
                        <div className="bg-gray-50 rounded-xl p-3 flex items-center justify-between border border-gray-200 shadow-inner">
                            <div className="flex items-center gap-3 text-gray-600">
                                <Clock size={18} className="text-gray-400" />
                                <span className="font-bold text-sm">{displayDate}</span>
                            </div>
                            <div className="bg-[#00C853] px-2 py-1 rounded-md text-xs font-mono text-white font-bold shadow-md shadow-green-500/30">
                                {displayTime}
                            </div>
                        </div>

                        {/* Rappel contextuel */}
                        <div className="flex items-center gap-4">
                            <div className="h-px bg-gray-200 flex-1"></div>
                            <span className="text-[10px] uppercase text-gray-400 font-bold tracking-wider">Connectez-vous à KIN ECO-MAP</span>
                            <div className="h-px bg-gray-200 flex-1"></div>
                        </div>

                        {/* 3. Choix du rôle utilisateur */}
                        <div className="grid grid-cols-2 gap-2">
                            {roleConfig.map((role) => (
                                <button
                                    key={role.id}
                                    onClick={() => setLoginRole(role.id)}
                                    className={`py-2.5 px-1 rounded-xl text-[10px] font-bold uppercase tracking-wider transition-all border ${
                                        loginRole === role.id 
                                        ? 'bg-white text-[#00C853] border-[#00C853] shadow-md transform scale-[1.02] ring-2 ring-[#00C853]/20' 
                                        : 'bg-gray-100 text-gray-500 border-transparent hover:bg-gray-200'
                                    }`}
                                >
                                    {role.label}
                                </button>
                            ))}
                        </div>

                        {/* 4. Champs de connexion */}
                        <div className="space-y-4">
                            {loginError && (
                                <div className="text-red-500 text-xs text-center bg-red-50 p-2 rounded-xl border border-red-100 flex items-center justify-center gap-2 font-medium">
                                    <AlertCircle size={14} /> {loginError}
                                </div>
                            )}

                            <div>
                                <label className="text-[10px] text-gray-500 uppercase font-bold mb-1 block pl-1">Identifiant</label>
                                <div className="bg-gray-50 rounded-xl flex items-center border border-gray-200 focus-within:border-[#00C853] focus-within:ring-2 focus-within:ring-[#00C853]/10 transition-all group">
                                    <div className="pl-3 text-gray-400 group-focus-within:text-[#00C853] transition-colors">
                                        <UserIcon size={18} />
                                    </div>
                                    <input 
                                        type="text" 
                                        placeholder={loginRole === UserType.ADMIN ? "admin@kinecomap.cd" : "Email ou Téléphone"}
                                        value={loginIdentifier}
                                        onChange={(e) => setLoginIdentifier(e.target.value)}
                                        className="bg-transparent w-full p-3.5 text-sm text-gray-800 placeholder-gray-400 outline-none font-medium"
                                    />
                                </div>
                            </div>

                            <div>
                                <label className="text-[10px] text-gray-500 uppercase font-bold mb-1 block pl-1">Mot de passe</label>
                                <div className="bg-gray-50 rounded-xl flex items-center border border-gray-200 focus-within:border-[#00C853] focus-within:ring-2 focus-within:ring-[#00C853]/10 transition-all pr-3 group">
                                    <div className="pl-3 text-gray-400 group-focus-within:text-[#00C853] transition-colors">
                                        <Lock size={18} />
                                    </div>
                                    <input 
                                        type={showPassword ? "text" : "password"} 
                                        placeholder="••••••••"
                                        value={loginPassword}
                                        onChange={(e) => setLoginPassword(e.target.value)}
                                        className="bg-transparent w-full p-3.5 text-sm text-gray-800 placeholder-gray-400 outline-none font-medium"
                                    />
                                    <button type="button" onClick={() => setShowPassword(!showPassword)} className="text-gray-400 hover:text-[#00C853] transition-colors">
                                        {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                                    </button>
                                </div>
                            </div>
                        </div>

                        {/* 5. Bouton de connexion */}
                        <button 
                            onClick={handleLoginSubmit}
                            disabled={isLoggingIn}
                            className="w-full bg-gradient-to-r from-[#00C853] to-[#009624] hover:from-[#00E676] hover:to-[#00C853] text-white font-black py-4 rounded-2xl shadow-lg shadow-green-500/30 transition-all transform active:scale-95 flex items-center justify-center gap-2 uppercase tracking-wide text-sm"
                        >
                            {isLoggingIn ? <Loader2 className="animate-spin" /> : 'Se Connecter'}
                        </button>

                        {/* 6. Autres liens */}
                        <div className="flex justify-between items-center pt-2 border-t border-gray-100">
                            <button onClick={() => { setShowLogin(false); setStep(1); }} className="flex items-center gap-2 text-gray-500 hover:text-gray-800 text-xs transition-colors font-medium">
                                <Home size={14} /> Page principale
                            </button>
                            <button onClick={() => { setShowForgotPass(true); setResetStep(1); }} className="text-[#2962FF] hover:text-blue-700 text-xs font-bold transition-colors">
                                Mot de passe oublié ?
                            </button>
                        </div>
                    </div>
                </div>

                {/* Footer Mentions */}
                <div className="absolute bottom-6 w-full text-center px-4">
                    <div className="flex justify-between max-w-md mx-auto text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                        <span>KIN ECO-MAP - v1.0.7</span>
                        <span>Développeurs @kinecomap</span>
                    </div>
                </div>
            </div>
        );
    };

    const renderForgotPassModal = () => (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setShowForgotPass(false)}></div>
            <div className="bg-white rounded-2xl w-full max-w-sm p-6 relative z-10 shadow-2xl animate-fade-in-up border border-gray-100">
                <button onClick={() => setShowForgotPass(false)} className="absolute top-4 right-4 text-gray-400 hover:text-gray-600">
                    <X size={20} />
                </button>
                <h3 className="text-xl font-bold text-gray-800 mb-2">
                    {resetStep === 1 ? 'Récupération' : 'Nouveau Mot de Passe'}
                </h3>

                {resetStep === 1 ? (
                    <>
                        <p className="text-sm text-gray-500 mb-6">Entrez votre identifiant pour recevoir un lien de réinitialisation.</p>
                        <form onSubmit={handleForgotPassRequest} className="space-y-4">
                            <input 
                                type="text" 
                                value={loginIdentifier}
                                onChange={(e) => setLoginIdentifier(e.target.value)}
                                placeholder="Email ou Téléphone"
                                className="w-full p-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-[#00C853] text-gray-800 outline-none"
                                required
                            />
                            <button type="submit" disabled={isLoggingIn} className="w-full py-3 bg-[#00C853] text-white rounded-xl font-bold hover:bg-green-600 transition-colors shadow-lg shadow-green-500/20">
                                {isLoggingIn ? <Loader2 className="animate-spin mx-auto" /> : 'Envoyer le code'}
                            </button>
                        </form>
                    </>
                ) : (
                    <>
                        <p className="text-sm text-gray-500 mb-6">Définissez votre nouveau mot de passe.</p>
                        <form onSubmit={handleResetConfirm} className="space-y-4">
                            <div>
                                <label className="text-xs font-bold text-gray-500 uppercase mb-1 block">Nouveau Mot de passe</label>
                                <input 
                                    type="password"
                                    value={newResetPassword}
                                    onChange={(e) => setNewResetPassword(e.target.value)}
                                    placeholder="••••••••"
                                    className="w-full p-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-[#00C853] text-gray-800 outline-none"
                                    required
                                />
                            </div>
                            <div>
                                <label className="text-xs font-bold text-gray-500 uppercase mb-1 block">Confirmer</label>
                                <input 
                                    type="password"
                                    value={confirmResetPassword}
                                    onChange={(e) => setConfirmResetPassword(e.target.value)}
                                    placeholder="••••••••"
                                    className="w-full p-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-[#00C853] text-gray-800 outline-none"
                                    required
                                />
                            </div>

                            <button type="submit" disabled={isLoggingIn} className="w-full py-3 bg-[#00C853] text-white rounded-xl font-bold hover:bg-green-600 transition-colors shadow-lg shadow-green-500/20">
                                {isLoggingIn ? <Loader2 className="animate-spin mx-auto" /> : 'Modifier le mot de passe'}
                            </button>
                        </form>
                    </>
                )}
            </div>
        </div>
    );

    const renderRegisterStep1 = () => (
        <div className="space-y-6">
            <div>
                <h2 className="text-2xl font-black text-gray-800 mb-2">Créer un compte</h2>
                <p className="text-gray-500">Commençons par les bases.</p>
            </div>
            <div className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                    <input type="text" placeholder="Prénom" className="w-full p-4 rounded-2xl bg-white border-2 border-transparent focus:border-[#00C853] outline-none text-gray-800 font-medium" value={formData.firstName} onChange={(e) => updateData('firstName', e.target.value)} />
                    <input type="text" placeholder="Nom" className="w-full p-4 rounded-2xl bg-white border-2 border-transparent focus:border-[#00C853] outline-none text-gray-800 font-medium" value={formData.lastName} onChange={(e) => updateData('lastName', e.target.value)} />
                </div>
                <input type="tel" placeholder="Téléphone (+243...)" className="w-full p-4 rounded-2xl bg-white border-2 border-transparent focus:border-[#00C853] outline-none text-gray-800 font-medium" value={formData.phone} onChange={(e) => updateData('phone', e.target.value)} />
                <input type="email" placeholder="Email (Optionnel)" className="w-full p-4 rounded-2xl bg-white border-2 border-transparent focus:border-[#00C853] outline-none text-gray-800 font-medium" value={formData.email} onChange={(e) => updateData('email', e.target.value)} />
            </div>
            <button onClick={handleSendOTP} disabled={isVerifyingOTP} className="w-full py-4 bg-[#00C853] text-white rounded-2xl font-black text-lg shadow-lg flex items-center justify-center gap-2">
                {isVerifyingOTP ? <Loader2 className="animate-spin" /> : <>Suivant <ChevronRight /></>}
            </button>
        </div>
    );

    const renderRegisterStep2_OTP = () => (
        <div className="space-y-6">
            <div>
                <h2 className="text-2xl font-black text-gray-800 mb-2">Vérification</h2>
                <p className="text-gray-500">Code envoyé au {formData.phone}</p>
            </div>
            <div className="flex justify-between gap-2">
                {otpCode.map((digit, idx) => (
                    <input
                        key={idx}
                        id={`otp-${idx}`}
                        type="text"
                        maxLength={1}
                        className="w-12 h-14 rounded-xl bg-white border-2 border-transparent focus:border-[#00C853] text-center text-xl font-bold text-gray-800 outline-none"
                        value={digit}
                        onChange={(e) => handleOtpChange(idx, e.target.value)}
                    />
                ))}
            </div>
            <div className="text-center text-sm text-gray-500">
                {otpTimer > 0 ? `Renvoyer dans ${otpTimer}s` : <button onClick={handleSendOTP} className="text-[#00C853] font-bold">Renvoyer le code</button>}
            </div>
            <button onClick={handleVerifyOTP} disabled={isVerifyingOTP} className="w-full py-4 bg-[#00C853] text-white rounded-2xl font-black text-lg shadow-lg flex items-center justify-center gap-2">
                {isVerifyingOTP ? <Loader2 className="animate-spin" /> : 'Vérifier'}
            </button>
        </div>
    );

    const renderRegisterStep3_Password = () => (
        <div className="space-y-6">
            <div>
                <h2 className="text-2xl font-black text-gray-800 mb-2">Sécurité</h2>
                <p className="text-gray-500">Choisissez un mot de passe fort.</p>
            </div>
            <div className="space-y-4">
                <input type="password" placeholder="Mot de passe" className="w-full p-4 rounded-2xl bg-white border-2 border-transparent focus:border-[#00C853] outline-none text-gray-800 font-medium" value={registerPassword} onChange={(e) => handlePasswordInput(e.target.value)} />

                {/* Password Strength Indicator */}
                <div className="flex gap-1 h-1.5 mt-2">
                    <div className={`flex-1 rounded-full ${passwordStrength >= 1 ? 'bg-red-500' : 'bg-gray-200'}`}></div>
                    <div className={`flex-1 rounded-full ${passwordStrength >= 2 ? 'bg-orange-500' : 'bg-gray-200'}`}></div>
                    <div className={`flex-1 rounded-full ${passwordStrength >= 3 ? 'bg-yellow-500' : 'bg-gray-200'}`}></div>
                    <div className={`flex-1 rounded-full ${passwordStrength >= 4 ? 'bg-green-500' : 'bg-gray-200'}`}></div>
                </div>

                <input type="password" placeholder="Confirmer mot de passe" className="w-full p-4 rounded-2xl bg-white border-2 border-transparent focus:border-[#00C853] outline-none text-gray-800 font-medium" value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)} />
            </div>
            <button onClick={() => setRegStep(4)} disabled={!registerPassword || registerPassword !== confirmPassword} className="w-full py-4 bg-[#00C853] text-white rounded-2xl font-black text-lg shadow-lg flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed">
                Suivant <ChevronRight />
            </button>
        </div>
    );

    const renderRegisterStep4_Role = () => (
        <div className="space-y-6">
            <div>
                <h2 className="text-2xl font-black text-gray-800 mb-2">Vous êtes ?</h2>
                <p className="text-gray-500">Sélectionnez votre type de profil.</p>
            </div>
            <div className="grid grid-cols-1 gap-4">
                {[
                    { id: UserType.CITIZEN, label: 'Citoyen / Ménage', icon: Home, desc: 'Gestion des déchets domestiques' },
                    { id: UserType.BUSINESS, label: 'Entreprise', icon: Building, desc: 'Solutions pour professionnels' },
                    { id: UserType.COLLECTOR, label: 'Collecteur', icon: Truck, desc: 'Je travaille dans la collecte' },
                ].map(type => (
                    <button 
                        key={type.id}
                        onClick={() => updateData('type', type.id)}
                        className={`p-6 rounded-3xl border-2 text-left transition-all ${formData.type === type.id ? 'border-[#00C853] bg-green-50' : 'border-transparent bg-white hover:border-gray-200'}`}
                    >
                        <div className="flex items-center gap-4">
                            <div className={`p-3 rounded-2xl ${formData.type === type.id ? 'bg-[#00C853] text-white' : 'bg-gray-100 text-gray-500'}`}>
                                <type.icon size={24} />
                            </div>
                            <div>
                                <h3 className="font-bold text-lg text-gray-800">{type.label}</h3>
                                <p className="text-sm text-gray-500">{type.desc}</p>
                            </div>
                        </div>
                    </button>
                ))}
            </div>
            <button onClick={() => setRegStep(5)} className="w-full py-4 bg-[#00C853] text-white rounded-2xl font-black text-lg shadow-lg flex items-center justify-center gap-2">
                Suivant <ChevronRight />
            </button>
        </div>
    );

    const renderRegisterStep5_Address = () => (
        <div className="space-y-6">
            <div>
                <h2 className="text-2xl font-black text-gray-800 mb-2">Localisation</h2>
                <p className="text-gray-500">Où devons-nous collecter ?</p>
            </div>
            <div className="space-y-4">
                <input type="text" placeholder="Adresse complète" className="w-full p-4 rounded-2xl bg-white border-2 border-transparent focus:border-[#00C853] outline-none text-gray-800 font-medium" value={formData.address} onChange={(e) => updateData('address', e.target.value)} />

                {/* Additional fields based on role */}
                {formData.type === UserType.BUSINESS && (
                    <>
                        <input type="text" placeholder="Nom de l'entreprise" className="w-full p-4 rounded-2xl bg-white border-2 border-transparent focus:border-[#00C853] outline-none text-gray-800 font-medium" value={formData.companyName} onChange={(e) => updateData('companyName', e.target.value)} />
                        <input type="text" placeholder="Secteur d'activité" className="w-full p-4 rounded-2xl bg-white border-2 border-transparent focus:border-[#00C853] outline-none text-gray-800 font-medium" value={formData.sector} onChange={(e) => updateData('sector', e.target.value)} />
                    </>
                )}

                {formData.type === UserType.CITIZEN && (
                    <select 
                        className="w-full p-4 rounded-2xl bg-white border-2 border-transparent focus:border-[#00C853] outline-none text-gray-800 font-medium"
                        value={formData.housingType}
                        onChange={(e) => updateData('housingType', e.target.value)}
                    >
                        <option value="Maison">Maison individuelle</option>
                        <option value="Appartement">Appartement</option>
                        <option value="Compound">Parcelle (Compound)</option>
                    </select>
                )}
            </div>
            <button onClick={() => setRegStep(6)} disabled={!formData.address} className="w-full py-4 bg-[#00C853] text-white rounded-2xl font-black text-lg shadow-lg flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed">
                Suivant <ChevronRight />
            </button>
        </div>
    );

    const renderRegisterStep6_Plan = () => {
        // Plans simulation
        const plans = [
            { id: 'standard', name: 'Standard', price: '10$', features: ['2x / semaine', 'Déchets ménagers'] },
            { id: 'plus', name: 'Plus', price: '15$', features: ['3x / semaine', 'Tri sélectif'], popular: true },
            { id: 'premium', name: 'Premium', price: '20$', features: ['Quotidien', 'Tout inclus'] },
        ];

        return (
            <div className="space-y-6">
                <div>
                    <h2 className="text-2xl font-black text-gray-800 mb-2">Abonnement</h2>
                    <p className="text-gray-500">Choisissez votre formule.</p>
                </div>
                <div className="space-y-3">
                    {plans.map(plan => (
                        <div 
                            key={plan.id}
                            onClick={() => updateData('subscription', plan.id)}
                            className={`p-5 rounded-3xl border-2 cursor-pointer transition-all relative ${formData.subscription === plan.id ? 'border-[#00C853] bg-green-50' : 'border-transparent bg-white hover:border-gray-200'}`}
                        >
                            {plan.popular && <span className="absolute top-0 right-0 bg-[#00C853] text-white text-xs font-bold px-3 py-1 rounded-bl-xl rounded-tr-xl">Populaire</span>}
                            <div className="flex justify-between items-center">
                                <div>
                                    <h3 className="font-bold text-gray-800">{plan.name}</h3>
                                    <p className="text-xs text-gray-500">{plan.features.join(' • ')}</p>
                                </div>
                                <div className="text-xl font-black text-[#2962FF]">{plan.price}</div>
                            </div>
                        </div>
                    ))}
                </div>

                <div className="flex items-center gap-3 py-2">
                    <div 
                        onClick={() => setAcceptedTerms(!acceptedTerms)}
                        className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center cursor-pointer transition-colors ${acceptedTerms ? 'bg-[#00C853] border-[#00C853] text-white' : 'border-gray-300'}`}
                    >
                        {acceptedTerms && <Check size={14} />}
                    </div>
                    <span className="text-xs text-gray-500">
                        J'accepte les <button onClick={() => setLegalModalType('terms')} className="text-[#2962FF] font-bold hover:underline">conditions d'utilisation</button> et la <button onClick={() => setLegalModalType('privacy')} className="text-[#2962FF] font-bold hover:underline">politique de confidentialité</button>.
                    </span>
                </div>

                <button onClick={handleRegisterSubmit} disabled={!acceptedTerms} className="w-full py-4 bg-[#00C853] text-white rounded-2xl font-black text-lg shadow-lg flex items-center justify-center gap-2 disabled:bg-gray-300 disabled:cursor-not-allowed">
                    {isLoggingIn ? <Loader2 className="animate-spin" /> : 'Créer mon compte'}
                </button>
            </div>
        );
    };

    if (showLogin) {
        return renderLogin();
    }

    return (
        <div className="h-screen bg-white flex flex-col md:items-center md:justify-center transition-colors duration-500">
            <div className="w-full h-full md:max-w-md md:h-[90vh] md:max-h-[850px] md:shadow-2xl md:rounded-[2.5rem] overflow-hidden relative flex flex-col bg-[#F5F7FA] border border-transparent">
                {step > 1 && (
                    <div className="p-6 flex items-center shrink-0">
                        <button onClick={() => {
                            if (regStep > 1) setRegStep(prev => prev - 1);
                            else handleBack();
                        }} className="p-3 bg-white rounded-full hover:bg-gray-100 transition-colors shadow-sm">
                            <ArrowLeft size={20} className="text-gray-600" />
                        </button>
                        <div className="ml-4 flex-1 h-2 bg-gray-200 rounded-full overflow-hidden">
                            <div className="h-full bg-[#00C853] transition-all duration-500 ease-out shadow-[0_0_10px_#00C853]" style={{ width: `${((regStep) / 6) * 100}%` }}></div>
                        </div>
                    </div>
                )}

                <div className="flex-1 overflow-y-auto no-scrollbar p-6">
                    {step === 1 && renderWelcome()}
                    {step === 2 && (
                        <div className="animate-fade-in">
                            {/* Reusing existing logic but wrapped in a container for consistent spacing if needed */}
                            {regStep === 1 && renderRegisterStep1()}
                            {regStep === 2 && renderRegisterStep2_OTP()}
                            {regStep === 3 && renderRegisterStep3_Password()}
                            {regStep === 4 && renderRegisterStep4_Role()}
                            {regStep === 5 && renderRegisterStep5_Address()}
                            {regStep === 6 && renderRegisterStep6_Plan()}
                        </div>
                    )}
                </div>
            </div>

            <LegalDocs 
                isOpen={!!legalModalType} 
                type={legalModalType} 
                onClose={() => setLegalModalType(null)} 
            />
            {showForgotPass && renderForgotPassModal()}
        </div>
    );
}

export enum UserType {
    CITIZEN = 'citizen',
    BUSINESS = 'business',
    COLLECTOR = 'collector',
    ADMIN = 'admin'
}

export type Theme = 'light' | 'dark';

export type Language = 'fr' | 'en';

export type UserPermission = 
    | 'manage_users' 
    | 'validate_docs' 
    | 'view_finance' 
    | 'manage_ads' 
    | 'export_data' 
    | 'manage_fleet'
    | 'manage_academy'
    | 'manage_communications'
    | 'manage_pos'
    | 'system_settings';

export interface SystemSettings {
    maintenanceMode: boolean;
    supportEmail: string;
    appVersion: string;
    force2FA: boolean;
    sessionTimeout: number;
    passwordPolicy: 'standard' | 'strong' | 'strict';
    marketplaceCommission: number; // Pourcentage (ex: 0.05 pour 5%)
}

export interface SubscriptionPlan {
    id: string;
    name: string;
    priceUSD: number;
    schedule: string;
    features: string[];
    popular?: boolean;
    isVariable?: boolean;
}

export interface User {
    id?: string; 
    firstName: string;
    lastName: string;
    phone: string;
    email?: string;
    type: UserType;
    address: string;
    points: number;
    collections: number;
    badges: number;
    subscription: 'standard' | 'plus' | 'premium' | 'special';
    companyName?: string;
    companyPhone?: string;
    sector?: string;
    vehicleType?: string;
    zone?: string;
    housingType?: string;
    permissions?: UserPermission[];
}

export interface Collector {
    id: number;
    name: string;
    lat: number;
    lng: number;
    status: 'active' | 'inactive';
    vehicle: string;
}

export interface ChatMessage {
    id: string;
    sender: 'user' | 'ai';
    text: string;
    timestamp: Date;
}

export interface QuizQuestion {
    id: string;
    question: string;
    options: string[];
    correctIndex: number;
}

export interface Course {
    id: string;
    title: string;
    description: string;
    progress: number;
    icon: string;
    color: string;
    videoUrl?: string; 
    status?: 'draft' | 'published';
    author?: string;
    quiz?: QuizQuestion[];
}

export interface Badge {
    id: string;
    title: string;
    description: string;
    icon: string;
    earned: boolean;
}

export interface NotificationItem {
    id: string;
    title: string;
    message: string;
    type: 'info' | 'success' | 'warning' | 'alert';
    time: string;
    read: boolean;
    targetUserId?: string | 'ADMIN' | 'ALL'; 
}

export type VehicleType = 'moto' | 'tricycle' | 'pickup' | 'camion' | 'chariot';

export interface Vehicle {
    id: string;
    name: string;
    type: VehicleType;
    plateNumber: string;
    gpsId: string;
    status: 'active' | 'maintenance' | 'stopped';
    batteryLevel: number;
    signalStrength: number;
    lat: number;
    lng: number;
    heading: number; // Direction en degrés (0-360)
    driverId?: string;
    lastUpdate: string;
}

export interface MarketplaceItem {
    id: string;
    sellerId: string;
    sellerName: string;
    title: string;
    category: 'electronics' | 'metal' | 'plastic' | 'other';
    description: string;
    weight: number; // kg
    price: number; // FC
    imageUrl: string;
    date: string;
    status: 'available' | 'pending_delivery' | 'sold';
}

export interface AdCampaign {
    id: string;
    title: string;
    partner: string;
    status: 'active' | 'paused' | 'ended';
    views: number;
    clicks: number;
    budget: number;
    spent: number;
    startDate: string;
    endDate: string;
    image: string;
}

export interface Partner {
    id: string;
    name: string;
    industry: string;
    contactName: string;
    email: string;
    phone: string;
    website?: string;
    activeCampaigns: number;
    totalBudget: number;
    logo: string;
    status: 'active' | 'inactive';
}

export enum AppView {
    LANDING = 'LANDING',
    ONBOARDING = 'ONBOARDING',
    DASHBOARD = 'DASHBOARD',
    MAP = 'MAP',
    ACADEMY = 'ACADEMY',
    MARKETPLACE = 'MARKETPLACE',
    BADGES = 'BADGES',
    PROFILE = 'PROFILE',
    NOTIFICATIONS = 'NOTIFICATIONS',
    SUBSCRIPTION = 'SUBSCRIPTION',
    PLANNING = 'PLANNING',
    SETTINGS = 'SETTINGS',
    ADMIN_USERS = 'ADMIN_USERS',
    ADMIN_ADS = 'ADMIN_ADS',
    ADMIN_SUBSCRIPTIONS = 'ADMIN_SUBSCRIPTIONS',
    ADMIN_VEHICLES = 'ADMIN_VEHICLES',
    ADMIN_ACADEMY = 'ADMIN_ACADEMY',
    ADMIN_PERMISSIONS = 'ADMIN_PERMISSIONS',
    COLLECTOR_JOBS = 'COLLECTOR_JOBS'
}

import React, { useState, useEffect, useRef } from 'react';
import { Onboarding } from './components/Onboarding';
import { LandingPage } from './components/LandingPage';
import { Dashboard } from './components/Dashboard';
import { MapView } from './components/Map';
import { Academy } from './components/Academy';
import { Marketplace } from './components/Marketplace'; 
import { Profile } from './components/Profile';
import { Layout } from './components/Layout';
import { Subscription } from './components/Subscription';
import { Planning } from './components/Planning';
import { Notifications } from './components/Notifications';
import { Settings } from './components/Settings';
import { AdminUsers } from './components/AdminUsers';
import { AdminAds } from './components/AdminAds';
import { AdminSubscriptions } from './components/AdminSubscriptions';
import { AdminVehicles } from './components/AdminVehicles';
import { AdminAcademy } from './components/AdminAcademy';
import { AdminPermissions } from './components/AdminPermissions';
import { CollectorJobs } from './components/CollectorJobs';
import { SplashScreen } from './components/SplashScreen';
import { User, AppView, UserType, Theme, SubscriptionPlan, Language, NotificationItem, SystemSettings } from './types';
import { SettingsAPI, UserAPI } from './services/api';
import { OfflineManager } from './services/offlineManager';
import { AlertTriangle, Lock } from 'lucide-react';

// Plans initiaux par défaut
const DEFAULT_PLANS: SubscriptionPlan[] = [
    { 
        id: 'standard', 
        name: 'Standard', 
        priceUSD: 10, 
        schedule: 'Mardi & Samedi',
        features: ['2 jours / semaine', 'Mardi & Samedi', 'Suivi basique'] 
    },
    { 
        id: 'plus', 
        name: 'Plus', 
        priceUSD: 15, 
        popular: true,
        schedule: 'Mardi, Jeudi & Samedi',
        features: ['3 jours / semaine', 'Mar, Jeu, Sam', 'Points doublés'] 
    },
    { 
        id: 'premium', 
        name: 'Premium', 
        priceUSD: 20, 
        schedule: 'Lun, Mer, Ven & Dim',
        features: ['4 jours / semaine', 'Lun, Mer, Ven, Dim', 'Certificat Eco', 'Support VIP'] 
    },
    { 
        id: 'special', 
        name: 'Spécial / Kilo', 
        priceUSD: 0, 
        isVariable: true,
        schedule: 'Sur demande',
        features: ['Paiement à la pesée', 'Idéal gros volumes', 'Horaires flexibles'] 
    },
];

const DEFAULT_NOTIFICATIONS: NotificationItem[] = [
    { id: '1', title: 'Bienvenue', message: 'Bienvenue sur KIN ECO-MAP ! Complétez votre profil pour commencer.', type: 'info', time: 'À l\'instant', read: false, targetUserId: 'ALL' }
];

function App() {
    // State
    const [loading, setLoading] = useState(true);

    // User State with LocalStorage Persistence for Offline Support
    const [user, setUser] = useState<User | null>(() => {
        try {
            const savedUser = localStorage.getItem('kinecomap_user');
            return savedUser ? JSON.parse(savedUser) : null;
        } catch (e) {
            return null;
        }
    });

    // Track if History API is supported/allowed in the current environment
    const historySupported = useRef(true);

    // NAVIGATION STATE: Improved History Stack
    const [history, setHistory] = useState<AppView[]>(() => {
        try {
            if (typeof window !== 'undefined' && window.history && window.history.state && window.history.state.history) {
                return window.history.state.history;
            }
        } catch (e) {
            historySupported.current = false;
        }

        try {
            const savedUser = localStorage.getItem('kinecomap_user');
            return savedUser ? [AppView.DASHBOARD] : [AppView.LANDING];
        } catch {
            return [AppView.LANDING];
        }
    });

    const view = history[history.length - 1] || AppView.LANDING;

    const [theme, setTheme] = useState<Theme>('light');
    const [language, setLanguage] = useState<Language>('fr');
    const [isRefreshing, setIsRefreshing] = useState(false);

    // Global Settings State
    const [systemSettings, setSystemSettings] = useState<SystemSettings>({
        maintenanceMode: false,
        supportEmail: 'support@kinecomap.cd',
        appVersion: '1.0.3',
        force2FA: false,
        sessionTimeout: 60,
        passwordPolicy: 'strong',
        marketplaceCommission: 0.05
    });

    // Subscription Data State
    const [plans, setPlans] = useState<SubscriptionPlan[]>(DEFAULT_PLANS);
    const [exchangeRate, setExchangeRate] = useState(2800);

    // Global Branding State
    const [appLogo, setAppLogo] = useState('./logo.png');

    // Notifications Global State
    const [notifications, setNotifications] = useState<NotificationItem[]>(DEFAULT_NOTIFICATIONS);

    // --- TOAST STATE ---
    const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' | 'info'; visible: boolean }>({
        message: '',
        type: 'success',
        visible: false
    });

    // Initial Load & Offline Manager Hook
    useEffect(() => {
        const loadInitData = async () => {
            try {
                if (historySupported.current && (!window.history.state || !window.history.state.history)) {
                    const initialStack = user ? [AppView.DASHBOARD] : [AppView.LANDING];
                    window.history.replaceState({ history: initialStack }, '', `#${initialStack[initialStack.length-1]}`);
                }
            } catch (e) {
                console.warn("History API restricted (Blob/Sandbox detected). Navigation will be internal only.");
                historySupported.current = false;
            }

            const settings = await SettingsAPI.get();
            setSystemSettings(settings);

            setTimeout(() => setLoading(false), 2500);
        };
        loadInitData();

        const handleOnline = () => {
            handleShowToast("Connexion rétablie. Synchronisation...", "info");
            OfflineManager.processQueue((task) => {
                handleShowToast(`Donnée synchronisée: ${task.type}`, "success");
            });
        };

        window.addEventListener('online', handleOnline);

        if (navigator.onLine) {
            OfflineManager.processQueue();
        }

        return () => window.removeEventListener('online', handleOnline);
    }, []); 

    useEffect(() => {
        const handlePopState = (event: PopStateEvent) => {
            if (event.state && event.state.history) {
                setHistory(event.state.history);
            } else {
                const fallbackStack = user ? [AppView.DASHBOARD] : [AppView.LANDING];
                setHistory(fallbackStack);
            }
        };

        window.addEventListener('popstate', handlePopState);
        return () => window.removeEventListener('popstate', handlePopState);
    }, [user]);

    useEffect(() => {
        if (user) {
            localStorage.setItem('kinecomap_user', JSON.stringify(user));
        } else {
            localStorage.removeItem('kinecomap_user');
        }
    }, [user]);

    useEffect(() => {
        const root = window.document.documentElement;
        const body = window.document.body;
        if (theme === 'dark') {
            root.classList.add('dark');
            body.classList.add('dark');
        } else {
            root.classList.remove('dark');
            body.classList.remove('dark');
        }
    }, [theme]);

    const handleThemeToggle = () => {
        setTheme(prev => prev === 'light' ? 'dark' : 'light');
        handleShowToast(theme === 'light' ? 'Mode sombre activé' : 'Mode clair activé', 'info');
    };

    const navigateTo = (newView: AppView) => {
        if (newView !== view) {
            const newStack = [...history, newView];
            setHistory(newStack);
            try {
                if (historySupported.current) {
                    window.history.pushState({ history: newStack }, '', `#${newView}`);
                }
            } catch (e) {
                historySupported.current = false;
            }
        }
    };

    const goBack = () => {
        if (history.length > 1) {
            if (historySupported.current) {
                try {
                    window.history.back(); 
                } catch (e) {
                    setHistory(prev => prev.slice(0, -1));
                }
            } else {
                setHistory(prev => prev.slice(0, -1));
            }
        }
    };

    const switchTab = (newRootView: AppView) => {
        if (newRootView !== view) {
            const newStack = [newRootView];
            setHistory(newStack);
            try {
                if (historySupported.current) {
                    window.history.pushState({ history: newStack }, '', `#${newRootView}`);
                }
            } catch (e) {
                historySupported.current = false;
            }
        }
    };

    const handleRefresh = async () => {
        if (!navigator.onLine) {
            handleShowToast("Mode hors ligne. Impossible d'actualiser.", "error");
            return;
        }
        setIsRefreshing(true);
        const settings = await SettingsAPI.get();
        setSystemSettings(settings);
        await OfflineManager.processQueue((task) => {
             handleShowToast("Données en attente envoyées", "success");
        });
        setTimeout(() => {
            setIsRefreshing(false);
            handleShowToast("Données mises à jour", "success");
        }, 1500);
    };

    const handleSendNotification = (targetId: string | 'ADMIN' | 'ALL', title: string, message: string, type: 'info' | 'success' | 'warning' | 'alert' = 'info') => {
        const newNotif: NotificationItem = {
            id: Date.now().toString(),
            title,
            message,
            type,
            time: 'À l\'instant',
            read: false,
            targetUserId: targetId
        };
        setNotifications(prev => [newNotif, ...prev]);
        if (user?.type === UserType.ADMIN || user?.type === UserType.COLLECTOR) {
             if (type === 'success' || type === 'info') {
                 handleShowToast(title + ": " + message, 'success');
             }
        }
    };

    const handleMarkAllRead = () => {
        if (!user) return;
        setNotifications(prev => prev.map(n => 
            (n.targetUserId === user.id || n.targetUserId === 'ALL' || (user.type === UserType.ADMIN && n.targetUserId === 'ADMIN')) 
            ? { ...n, read: true } 
            : n
        ));
        handleShowToast("Toutes les notifications marquées comme lues", "info");
    };

    const handleShowToast = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
        setToast({ message, type, visible: true });
        setTimeout(() => {
            setToast(prev => ({ ...prev, visible: false }));
        }, 3000);
    };

    const handleOnboardingComplete = (data: Partial<User>) => {
        const newUser: User = {
            id: 'u' + Date.now(),
            firstName: data.firstName || 'Utilisateur',
            lastName: data.lastName || '',
            phone: data.phone || '',
            type: data.type || UserType.CITIZEN,
            address: data.address || 'Kinshasa',
            points: 0,
            collections: 0,
            badges: 0,
            subscription: data.subscription || 'standard',
            companyName: data.companyName,
            companyPhone: data.companyPhone,
            sector: data.sector,
            vehicleType: data.vehicleType,
            housingType: data.housingType,
            zone: data.zone,
            permissions: data.type === UserType.ADMIN ? 
                ['manage_users', 'validate_docs', 'view_finance', 'manage_ads', 'export_data', 'system_settings', 'manage_fleet', 'manage_academy', 'manage_communications', 'manage_pos'] : 
                undefined
        };
        if (!navigator.onLine) {
            OfflineManager.addToQueue('UPDATE_PROFILE', newUser);
            handleShowToast("Compte créé hors ligne. Synchronisation en attente.", "info");
        }
        setUser(newUser);
        const newStack = [AppView.DASHBOARD];
        setHistory(newStack);
        try {
            if (historySupported.current) {
                window.history.pushState({ history: newStack }, '', `#${AppView.DASHBOARD}`);
            }
        } catch (e) {
            historySupported.current = false;
        }
        handleShowToast(`Bienvenue, ${newUser.firstName} !`, 'success');
    };

    const handleLogout = () => {
        setUser(null);
        const newStack = [AppView.LANDING];
        setHistory(newStack);
        try {
            if (historySupported.current) {
                window.history.pushState({ history: newStack }, '', '#landing');
            }
        } catch (e) {}
        localStorage.removeItem('kinecomap_user');
        handleShowToast("Déconnexion réussie", "info");
    };

    const handleUpdateUserPlan = (newPlan: 'standard' | 'plus' | 'premium' | 'special') => {
        if (user) {
            const updatedUser = { ...user, subscription: newPlan };
            setUser(updatedUser);
            if (!navigator.onLine) {
                OfflineManager.addToQueue('UPDATE_PROFILE', { subscription: newPlan });
                handleShowToast("Plan mis à jour (Sauvegardé hors ligne)", "info");
            } else {
                handleShowToast("Plan mis à jour avec succès", "success");
            }
        }
    };

    const handleUpdateProfile = async (updatedData: Partial<User>) => {
        if (!user) return;
        const updatedUser = { ...user, ...updatedData };
        setUser(updatedUser);
        if (updatedUser.id) {
            await UserAPI.update(updatedUser as User & { id: string });
        }
        if (!navigator.onLine) {
            OfflineManager.addToQueue('UPDATE_PROFILE', updatedUser);
            handleShowToast("Profil mis à jour (Hors ligne)", "info");
        } else {
            handleShowToast("Profil mis à jour avec succès", "success");
        }
    };

    const handleUpdatePlanConfig = (updatedPlan: SubscriptionPlan) => {
        setPlans(prev => prev.map(p => p.id === updatedPlan.id ? updatedPlan : p));
        handleShowToast("Configuration du plan enregistrée", "success");
    };

    const handleUpdateExchangeRate = (rate: number) => {
        setExchangeRate(rate);
        handleShowToast(`Nouveau taux : 1$ = ${rate} FC`, "success");
    };

    const handleUpdateSystemSettings = async (newSettings: SystemSettings) => {
        setSystemSettings(newSettings);
        await SettingsAPI.update(newSettings);
    };

    const userNotifications = notifications.filter(n => {
        if (!user) return false;
        if (n.targetUserId === 'ALL') return true;
        if (n.targetUserId === 'ADMIN' && user.type === UserType.ADMIN) return true;
        return n.targetUserId === user.id;
    });

    const unreadCount = userNotifications.filter(n => !n.read).length;

    const renderContent = () => {
        if (!user) {
            if (view === AppView.LANDING) {
                return <LandingPage onStart={() => navigateTo(AppView.ONBOARDING)} />;
            }
            if (view === AppView.ONBOARDING) {
                return <Onboarding onComplete={handleOnboardingComplete} appLogo={appLogo} onToast={handleShowToast} />;
            }
            return null;
        }

        if (systemSettings.maintenanceMode && user.type !== UserType.ADMIN) {
            return (
                <div className="flex flex-col items-center justify-center h-screen bg-gray-50 dark:bg-gray-900 p-6 text-center animate-fade-in">
                    <div className="w-24 h-24 bg-red-100 dark:bg-red-900/20 rounded-full flex items-center justify-center mb-6 text-red-500 animate-pulse">
                        <AlertTriangle size={48} />
                    </div>
                    <h1 className="text-3xl font-black text-gray-800 dark:text-white mb-2">Maintenance en cours</h1>
                    <p className="text-gray-500 dark:text-gray-400 max-w-md mb-8">
                        L'application KIN ECO-MAP est momentanément inaccessible pour une mise à jour technique.
                        <br/>Veuillez revenir dans quelques instants.
                    </p>
                    <div className="bg-white dark:bg-gray-800 p-4 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700 flex items-center gap-3">
                        <Lock size={20} className="text-gray-400" />
                        <span className="text-sm font-mono text-gray-600 dark:text-gray-300">Code: MAINTENANCE_MODE_ACTIVE</span>
                    </div>
                    <button onClick={handleLogout} className="mt-8 text-sm text-gray-400 hover:text-gray-600 underline">Se déconnecter</button>
                </div>
            );
        }

        const commonProps = { onToast: handleShowToast };

        switch (view) {
            case AppView.DASHBOARD:
                return <Dashboard user={user} onChangeView={navigateTo} {...commonProps} />;
            case AppView.MAP:
                return <MapView user={user} onBack={goBack} />;
            case AppView.ACADEMY:
                return <Academy onBack={goBack} />;
            case AppView.MARKETPLACE: 
                return <Marketplace user={user} onBack={goBack} systemSettings={systemSettings} {...commonProps} />;
            case AppView.PROFILE:
                return (
                    <Profile 
                        user={user} 
                        theme={theme}
                        onToggleTheme={handleThemeToggle}
                        onBack={goBack} 
                        onLogout={handleLogout}
                        onManageSubscription={() => navigateTo(AppView.SUBSCRIPTION)}
                        onSettings={() => navigateTo(AppView.SETTINGS)}
                        onUpdateProfile={handleUpdateProfile}
                        {...commonProps}
                    />
                );
            case AppView.SUBSCRIPTION:
                return (
                    <Subscription 
                        user={user} 
                        onBack={goBack} 
                        onUpdatePlan={handleUpdateUserPlan}
                        plans={plans}
                        exchangeRate={exchangeRate}
                        {...commonProps}
                    />
                );
            case AppView.PLANNING:
                return <Planning onBack={goBack} />;
            case AppView.NOTIFICATIONS:
                return (
                    <Notifications 
                        onBack={goBack} 
                        notifications={userNotifications}
                        onMarkAllRead={handleMarkAllRead}
                    />
                );
            case AppView.SETTINGS:
                return (
                    <Settings 
                        user={user}
                        theme={theme}
                        onToggleTheme={handleThemeToggle}
                        onBack={goBack} 
                        onLogout={handleLogout}
                        currentLanguage={language}
                        onLanguageChange={setLanguage}
                        {...commonProps}
                    />
                );
            case AppView.ADMIN_USERS:
                return <AdminUsers currentUser={user} onBack={goBack} onNotify={handleSendNotification} {...commonProps} />;
            case AppView.ADMIN_ADS:
                return <AdminAds onBack={goBack} {...commonProps} />;
            case AppView.ADMIN_SUBSCRIPTIONS:
                return (
                    <AdminSubscriptions 
                        onBack={goBack} 
                        plans={plans}
                        exchangeRate={exchangeRate}
                        onUpdatePlan={handleUpdatePlanConfig}
                        onUpdateExchangeRate={handleUpdateExchangeRate}
                        currentLogo={appLogo}
                        onUpdateLogo={setAppLogo}
                        systemSettings={systemSettings}
                        onUpdateSystemSettings={handleUpdateSystemSettings}
                        {...commonProps}
                    />
                );
            case AppView.ADMIN_ACADEMY: 
                return <AdminAcademy onBack={goBack} {...commonProps} />;
            case AppView.ADMIN_VEHICLES:
                return <AdminVehicles onBack={goBack} {...commonProps} />;
            case AppView.ADMIN_PERMISSIONS:
                return <AdminPermissions onBack={goBack} {...commonProps} />;
            case AppView.COLLECTOR_JOBS:
                return (
                    <CollectorJobs 
                        user={user} 
                        onBack={goBack} 
                        onNotify={handleSendNotification}
                        {...commonProps}
                    />
                );
            default:
                return <Dashboard user={user} onChangeView={navigateTo} />;
        }
    };

    if (loading) {
        return <SplashScreen appLogo={appLogo} />;
    }

    if (view === AppView.LANDING || (!user && view === AppView.ONBOARDING)) {
        return renderContent();
    }

    return (
        <Layout 
            currentView={view} 
            onChangeView={switchTab}
            onLogout={handleLogout} 
            onRefresh={handleRefresh}
            isRefreshing={isRefreshing}
            user={user}
            unreadNotifications={unreadCount}
            appLogo={appLogo}
            toast={toast}
            onCloseToast={() => setToast(prev => ({...prev, visible: false}))}
        >
            {renderContent()}
        </Layout>
    );
}

export default App;

