import { AlertTriangle, Lock } from 'lucide-react';

const DEFAULT_PLANS: SubscriptionPlan[] = [
    { id: 'standard', name: 'Standard', priceUSD: 10, schedule: 'Mardi & Samedi', features: ['2 jours / semaine', 'Mardi & Samedi', 'Suivi basique'] },
