import React, { useState, useEffect } from 'react';
import { ChevronRight, ArrowLeft, Home, Building, Truck, Check, CreditCard, MapPin, LogIn, User as UserIcon, Shield, Lock, Phone, Eye, EyeOff, AlertCircle, Mail, Smartphone, RefreshCw, KeyRound, Globe, Loader2, X, Clock, Briefcase, GraduationCap, ShieldCheck } from 'lucide-react';
import { UserType, User } from '../types';
import { LegalDocs } from './LegalDocs';
import { UserAPI } from '../services/api';
import { isSupabaseConfigured } from '../services/supabaseClient';

interface OnboardingProps {
    onComplete: (user: Partial<User>) => void;
    appLogo?: string;
    onToast?: (msg: string, type: 'success' | 'error' | 'info') => void;
    initialShowLogin?: boolean; // Ajouté pour permettre l'accès direct
}

export const Onboarding: React.FC<OnboardingProps> = ({ onComplete, appLogo = './logo.png', onToast, initialShowLogin = false }) => {
    const [step, setStep] = useState(initialShowLogin ? 2 : 1);
    const [showLogin, setShowLogin] = useState(initialShowLogin);
    const [showForgotPass, setShowForgotPass] = useState(false);

    // Legal Docs State
    const [acceptedTerms, setAcceptedTerms] = useState(false);
    const [legalModalType, setLegalModalType] = useState<'terms' | 'privacy' | null>(null);

    // Login State
    const [loginRole, setLoginRole] = useState<UserType>(UserType.CITIZEN);
    const [loginIdentifier, setLoginIdentifier] = useState('');
    const [loginPassword, setLoginPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [isLoggingIn, setIsLoggingIn] = useState(false);
    const [loginError, setLoginError] = useState<string | null>(null);
    const [currentTime, setCurrentTime] = useState(new Date());

    // Reset password state
    const [resetStep, setResetStep] = useState<1 | 2>(1); 
    const [newResetPassword, setNewResetPassword] = useState('');
    const [confirmResetPassword, setConfirmResetPassword] = useState('');

    // Register State
    const [regStep, setRegStep] = useState(1);
    const [otpCode, setOtpCode] = useState(['', '', '', '', '', '']);
    const [isVerifyingOTP, setIsVerifyingOTP] = useState(false);
    const [otpTimer, setOtpTimer] = useState(0);

    const [registerPassword, setRegisterPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [passwordStrength, setPasswordStrength] = useState(0); 

    const [formData, setFormData] = useState<Partial<User>>({
        firstName: '', lastName: '', phone: '', email: '',
        type: UserType.CITIZEN, address: '', subscription: 'plus',
        companyName: '', companyPhone: '', sector: '', vehicleType: '', housingType: 'Maison'
    });

    useEffect(() => {
        const timer = setInterval(() => setCurrentTime(new Date()), 1000);
        return () => clearInterval(timer);
    }, []);

    // Met à jour l'affichage si la prop change (ex: navigation répétée)
    useEffect(() => {
        if (initialShowLogin) {
            setShowLogin(true);
            setStep(2);
        }
    }, [initialShowLogin]);

    const handleNext = () => setStep(prev => prev + 1);
    const handleBack = () => setStep(prev => prev - 1);
    const updateData = (key: string, value: any) => setFormData(prev => ({ ...prev, [key]: value }));

    const handleSendOTP = async () => {
        if (!formData.firstName || !formData.lastName || !formData.phone) {
            if(onToast) onToast("Veuillez remplir tous les champs obligatoires", "error");
            return;
        }
        setIsVerifyingOTP(true);
        setTimeout(() => {
            setIsVerifyingOTP(false);
            setRegStep(2);
            setOtpTimer(60);
            if(onToast) onToast(`Code envoyé au ${formData.phone}`, "info");
        }, 1500);
    };

    const handleVerifyOTP = async () => {
        const code = otpCode.join('');
        if (code.length !== 6) {
            if(onToast) onToast("Code incomplet", "error");
            return;
        }
        setIsVerifyingOTP(true);
        const isValid = await UserAPI.verifyOTP(code);
        setIsVerifyingOTP(false);
        if (isValid) {
            if(onToast) onToast("Numéro vérifié avec succès", "success");
            setRegStep(3);
        } else {
            if(onToast) onToast("Code incorrect (Essayez 123456)", "error");
            setOtpCode(['', '', '', '', '', '']);
        }
    };

    const handleLoginSubmit = async () => {
        if (!loginIdentifier || !loginPassword) {
            setLoginError("Veuillez remplir tous les champs");
            return;
        }
        setIsLoggingIn(true);
        setLoginError(null);
        try {
            const user = await UserAPI.login(loginIdentifier, loginPassword);
            if (user) {
                if(onToast) onToast(`Bon retour, ${user.firstName} !`, "success");
                onComplete(user);
            } else {
                setLoginError("Identifiants incorrects ou utilisateur introuvable.");
            }
        } catch (err) {
            setLoginError("Une erreur est survenue.");
        } finally {
            setIsLoggingIn(false);
        }
    };

    const renderWelcome = () => (
        <div className="flex flex-col items-center justify-center h-full text-center p-8 bg-black relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-full bg-[url('https://images.unsplash.com/photo-1542601906990-b4d3fb778b09?q=80&w=2574&auto=format&fit=crop')] bg-cover bg-center opacity-40 mix-blend-overlay"></div>
            <div className="absolute bottom-[-10%] right-[-10%] w-[80%] h-[50%] bg-[#00C853] rounded-full blur-[150px] opacity-20"></div>
            <div className="relative z-10 w-full max-w-md mx-auto">
                <div className="w-28 h-28 bg-white/10 backdrop-blur-xl rounded-[2rem] flex items-center justify-center mb-10 shadow-2xl border border-white/20 mx-auto animate-float">
                     <img src={appLogo} alt="Logo" className="w-full h-full object-contain p-4" />
                </div>
                <h1 className="text-5xl font-black mb-4 tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-white via-gray-200 to-gray-400">KIN ECO-MAP</h1>
                <p className="text-lg text-gray-300 mb-12 font-light max-w-xs mx-auto leading-relaxed">Le futur de la propreté urbaine.<br/><span className="text-[#00C853] font-bold">Intelligent. Connecté. Vert.</span></p>
                <div className="w-full space-y-4">
                    <button onClick={() => { setStep(2); setShowLogin(false); }} className="w-full bg-[#00C853] hover:bg-[#00E676] text-black font-black py-4 rounded-2xl shadow-lg transition-all flex items-center justify-center gap-2 transform active:scale-95 text-lg">COMMENCER <ChevronRight size={24} /></button>
                    <button onClick={() => { setShowLogin(true); setStep(2); }} className="w-full bg-white/5 hover:bg-white/10 backdrop-blur-md border border-white/20 text-white font-bold py-4 rounded-2xl transition-all flex items-center justify-center gap-2 tracking-wide">SE CONNECTER <LogIn size={20} /></button>
                </div>
            </div>
        </div>
    );

