import React, { useState, useEffect } from 'react';
import { ChevronRight, ArrowLeft, Home, LogIn, User as UserIcon, Shield, Lock, Phone, Eye, EyeOff, AlertCircle, Loader2, Clock, Globe, ShieldCheck } from 'lucide-react';
import { UserType, User } from '../types';
import { LegalDocs } from './LegalDocs';
import { UserAPI } from '../services/api';

interface OnboardingProps {
    onComplete: (user: Partial<User>) => void;
    onBackToLanding: () => void;
    appLogo?: string;
    onToast?: (msg: string, type: 'success' | 'error' | 'info') => void;
    initialShowLogin?: boolean;
}

export const Onboarding: React.FC<OnboardingProps> = ({ onComplete, onBackToLanding, appLogo = './logo.png', onToast, initialShowLogin = false }) => {
    // État gérant l'affichage : soit Connexion, soit Inscription.
    const [showLogin, setShowLogin] = useState(initialShowLogin);
    const [showForgotPass, setShowForgotPass] = useState(false);

    // Legal Docs State
    const [legalModalType, setLegalModalType] = useState<'terms' | 'privacy' | null>(null);

    // Login State
    const [loginRole, setLoginRole] = useState<UserType>(UserType.CITIZEN);
    const [loginIdentifier, setLoginIdentifier] = useState('');
    const [loginPassword, setLoginPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [isLoggingIn, setIsLoggingIn] = useState(false);
    const [loginError, setLoginError] = useState<string | null>(null);
    const [currentTime, setCurrentTime] = useState(new Date());

    // Register State
    const [isVerifyingOTP, setIsVerifyingOTP] = useState(false);

    const [formData, setFormData] = useState<Partial<User>>({
        firstName: '', lastName: '', phone: '', email: '',
        type: UserType.CITIZEN, address: '', subscription: 'plus'
    });

    useEffect(() => {
        const timer = setInterval(() => setCurrentTime(new Date()), 1000);
        return () => clearInterval(timer);
    }, []);

    // Met à jour l'affichage si la prop change
    useEffect(() => {
        setShowLogin(initialShowLogin);
    }, [initialShowLogin]);

    const updateData = (key: string, value: any) => setFormData(prev => ({ ...prev, [key]: value }));

    const handleSendOTP = async () => {
        if (!formData.firstName || !formData.lastName || !formData.phone) {
            if(onToast) onToast("Veuillez remplir tous les champs obligatoires", "error");
            return;
        }
        setIsVerifyingOTP(true);
        setTimeout(() => {
            setIsVerifyingOTP(false);
            if(onToast) onToast(`Inscription réussie (Simulation)`, "success");
            onComplete(formData);
        }, 1500);
    };

    const handleLoginSubmit = async () => {
        if (!loginIdentifier || !loginPassword) {
            setLoginError("Veuillez remplir tous les champs");
            return;
        }
        setIsLoggingIn(true);
        setLoginError(null);
        try {
            const user = await UserAPI.login(loginIdentifier, loginPassword);
            if (user) {
                if(onToast) onToast(`Bon retour, ${user.firstName} !`, "success");
                onComplete(user);
            } else {
                setLoginError("Identifiants incorrects ou utilisateur introuvable.");
            }
        } catch (err) {
            setLoginError("Une erreur est survenue.");
        } finally {
            setIsLoggingIn(false);
        }
    };

    const renderLogin = () => {
        const formattedDate = currentTime.toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });
        const displayTime = currentTime.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit', second: '2-digit' });
        const roleConfig = [
            { id: UserType.ADMIN, label: 'Admin' }, 
            { id: UserType.COLLECTOR, label: 'Collecteur' }, 
            { id: UserType.CITIZEN, label: 'Citoyen' }, 
            { id: UserType.BUSINESS, label: 'Entreprise' }
        ];

        return (
            <div className="flex items-center justify-center min-h-screen bg-[#F5F7FA] relative overflow-hidden p-4">
                <div className="relative w-full max-w-md bg-white/80 backdrop-blur-xl rounded-[2.5rem] border border-white/60 shadow-2xl flex flex-col p-8 space-y-6">
                    <div className="text-center">
                        <span className="text-[#00C853] font-black italic tracking-widest text-[10px] bg-green-50 px-3 py-1 rounded-full border border-green-100 uppercase">Connexion</span>
                        <h2 className="text-3xl font-black text-gray-800 mt-2 mb-4 tracking-tighter uppercase">KIN ECO-MAP</h2>
                        <div className="flex justify-center gap-3">
                            <span className="bg-gray-100 px-3 py-1 rounded-full text-[10px] text-gray-600 flex items-center gap-1 border font-bold"><ShieldCheck size={12} className="text-[#00C853]" /> Sécurisé</span>
                            <span className="bg-gray-100 px-3 py-1 rounded-full text-[10px] text-gray-600 flex items-center gap-1 border font-bold"><Globe size={12} className="text-[#2962FF]" /> Écologie</span>
                        </div>
                    </div>
                    <div className="bg-gray-50 rounded-xl p-3 flex items-center justify-between border border-gray-200">
                        <div className="flex items-center gap-3 text-gray-600"><Clock size={18} className="text-gray-400" /><span className="font-bold text-sm">{formattedDate}</span></div>
                        <div className="bg-[#00C853] px-2 py-1 rounded-md text-xs text-white font-bold">{displayTime}</div>
                    </div>
                    <div className="grid grid-cols-2 gap-2">
                        {roleConfig.map((role) => (
                            <button key={role.id} onClick={() => setLoginRole(role.id as any)} className={`py-2.5 px-1 rounded-xl text-[10px] font-bold uppercase transition-all border ${loginRole === role.id ? 'bg-white text-[#00C853] border-[#00C853] shadow-md ring-2 ring-[#00C853]/20' : 'bg-gray-100 text-gray-500 border-transparent hover:bg-gray-200'}`}>{role.label}</button>
                        ))}
                    </div>
                    <div className="space-y-4">
                        {loginError && <div className="text-red-500 text-xs text-center bg-red-50 p-2 rounded-xl border border-red-100 flex items-center justify-center gap-2"><AlertCircle size={14} /> {loginError}</div>}
                        <div className="bg-gray-50 rounded-xl flex items-center border border-gray-200 focus-within:border-[#00C853] pr-3 group">
                            <div className="pl-3 text-gray-400 group-focus-within:text-[#00C853]"><UserIcon size={18} /></div>
                            <input type="text" placeholder="Email ou Téléphone" value={loginIdentifier} onChange={(e) => setLoginIdentifier(e.target.value)} className="bg-transparent w-full p-3.5 text-sm text-gray-800 outline-none" />
                        </div>
                        <div className="bg-gray-50 rounded-xl flex items-center border border-gray-200 focus-within:border-[#00C853] pr-3 group">
                            <div className="pl-3 text-gray-400 group-focus-within:text-[#00C853]"><Lock size={18} /></div>
                            <input type={showPassword ? "text" : "password"} placeholder="Mot de passe" value={loginPassword} onChange={(e) => setLoginPassword(e.target.value)} className="bg-transparent w-full p-3.5 text-sm text-gray-800 outline-none" />
                            <button onClick={() => setShowPassword(!showPassword)}>{showPassword ? <EyeOff size={18} /> : <Eye size={18} />}</button>
                        </div>
                    </div>
                    <button onClick={handleLoginSubmit} disabled={isLoggingIn} className="w-full bg-gradient-to-r from-[#00C853] to-[#009624] text-white font-black py-4 rounded-2xl shadow-lg flex items-center justify-center gap-2 uppercase tracking-wide text-sm">{isLoggingIn ? <Loader2 className="animate-spin" /> : 'Se Connecter'}</button>
                    <div className="flex justify-between items-center pt-2 border-t border-gray-100">
                        <button onClick={onBackToLanding} className="flex items-center gap-2 text-gray-500 hover:text-gray-800 text-xs font-medium"><Home size={14} /> Accueil</button>
                        <button onClick={() => setShowForgotPass(true)} className="text-[#2962FF] hover:text-blue-700 text-xs font-bold transition-colors">Mot de passe oublié ?</button>
                    </div>
                </div>
            </div>
        );
    };

    if (showLogin) return renderLogin();

    return (
        <div className="h-screen bg-[#F5F7FA] flex flex-col md:items-center md:justify-center transition-colors duration-500">
            <div className="w-full h-full md:max-w-md md:h-[90vh] md:max-h-[850px] md:shadow-2xl md:rounded-[2.5rem] overflow-hidden relative flex flex-col bg-white">
                <div className="p-6 flex items-center shrink-0 bg-[#F5F7FA]">
                    <button onClick={onBackToLanding} className="p-3 bg-white rounded-full shadow-sm"><ArrowLeft size={20} className="text-gray-600" /></button>
                    <div className="ml-4 flex-1 h-2 bg-gray-200 rounded-full overflow-hidden">
                        <div className="h-full bg-[#00C853] transition-all duration-500 shadow-[0_0_10px_#00C853]" style={{ width: `50%` }}></div>
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto no-scrollbar p-6 space-y-6">
                    <h2 className="text-3xl font-black text-gray-800 tracking-tight">Rejoindre<br/><span className="text-[#00C853]">KIN ECO-MAP</span></h2>
                    <p className="text-sm text-gray-500 font-medium leading-relaxed">Créez votre compte pour commencer à gérer vos déchets intelligemment à Kinshasa.</p>

                    <div className="space-y-4">
                        <div className="grid grid-cols-2 gap-4">
                            <input placeholder="Prénom" className="w-full p-4 rounded-2xl bg-[#F5F7FA] border border-gray-100 outline-none focus:ring-2 focus:ring-[#00C853] font-medium" value={formData.firstName} onChange={(e) => updateData('firstName', e.target.value)} />
                            <input placeholder="Nom" className="w-full p-4 rounded-2xl bg-[#F5F7FA] border border-gray-100 outline-none focus:ring-2 focus:ring-[#00C853] font-medium" value={formData.lastName} onChange={(e) => updateData('lastName', e.target.value)} />
                        </div>
                        <input type="tel" placeholder="N° de téléphone" className="w-full p-4 rounded-2xl bg-[#F5F7FA] border border-gray-100 outline-none focus:ring-2 focus:ring-[#00C853] font-medium" value={formData.phone} onChange={(e) => updateData('phone', e.target.value)} />

                        <div className="bg-blue-50 p-4 rounded-2xl border border-blue-100">
                            <p className="text-xs text-blue-600 font-bold mb-1 uppercase tracking-widest">Type de compte</p>
                            <select 
                                className="w-full bg-transparent outline-none font-bold text-gray-800"
                                value={formData.type}
                                onChange={(e) => updateData('type', e.target.value)}
                            >
                                <option value={UserType.CITIZEN}>Eco-Citoyen (Ménage)</option>
                                <option value={UserType.BUSINESS}>Eco-Entreprise (Commerce)</option>
                                <option value={UserType.COLLECTOR}>Collecteur (Opérateur)</option>
                            </select>
                        </div>

                        <button onClick={handleSendOTP} disabled={isVerifyingOTP} className="w-full py-5 bg-[#00C853] text-white rounded-2xl font-black shadow-xl shadow-green-500/20 flex items-center justify-center gap-2 transform active:scale-95 transition-all text-lg">
                            {isVerifyingOTP ? <Loader2 className="animate-spin" /> : <>S'INSCRIRE <ChevronRight /></>}
                        </button>
                    </div>

                    <div className="text-center pt-4">
                        <button onClick={() => setShowLogin(true)} className="text-gray-500 font-bold text-sm">Déjà un compte ? <span className="text-[#2962FF]">Se connecter</span></button>
                    </div>
                </div>
            </div>
            <LegalDocs isOpen={!!legalModalType} type={legalModalType} onClose={() => setLegalModalType(null)} />
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { ChevronRight, ArrowLeft, Home, LogIn, User as UserIcon, Shield, Lock, Phone, Eye, EyeOff, AlertCircle, Loader2, Clock, Globe, ShieldCheck, Mail, MapPin, CheckCircle2 } from 'lucide-react';
import { UserType, User } from '../types';
import { LegalDocs } from './LegalDocs';
import { UserAPI } from '../services/api';

interface OnboardingProps {
    onComplete: (user: Partial<User>) => void;
    onBackToLanding: () => void;
    appLogo?: string;
    onToast?: (msg: string, type: 'success' | 'error' | 'info') => void;
    initialShowLogin?: boolean;
}

export const Onboarding: React.FC<OnboardingProps> = ({ onComplete, onBackToLanding, appLogo = './logo.png', onToast, initialShowLogin = false }) => {
    const [showLogin, setShowLogin] = useState(initialShowLogin);
    const [showForgotPass, setShowForgotPass] = useState(false);
    const [legalModalType, setLegalModalType] = useState<'terms' | 'privacy' | null>(null);

    // Common State
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [showPassword, setShowPassword] = useState(false);
    const [currentTime, setCurrentTime] = useState(new Date());

    // Login State
    const [loginRole, setLoginRole] = useState<UserType>(UserType.CITIZEN);
    const [loginIdentifier, setLoginIdentifier] = useState('');
    const [loginPassword, setLoginPassword] = useState('');

    // Register Multi-step State
    const [regStep, setRegStep] = useState(1);
    const [registerPassword, setRegisterPassword] = useState('');
    const [formData, setFormData] = useState<Partial<User>>({
        firstName: '', lastName: '', phone: '', email: '',
        type: UserType.CITIZEN, address: '', subscription: 'standard'
    });

    useEffect(() => {
        const timer = setInterval(() => setCurrentTime(new Date()), 1000);
        return () => clearInterval(timer);
    }, []);

    useEffect(() => {
        setShowLogin(initialShowLogin);
        if (!initialShowLogin) setRegStep(1);
    }, [initialShowLogin]);

    const updateData = (key: string, value: any) => {
        setFormData(prev => ({ ...prev, [key]: value }));
        setError(null);
    };

    // --- LOGIC: LOGIN ---
    const handleLoginSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!loginIdentifier || !loginPassword) {
            setError("Veuillez remplir tous les champs");
            return;
        }
        setIsLoading(true);
        setError(null);
        try {
            const user = await UserAPI.login(loginIdentifier, loginPassword);
            if (user) {
                if(onToast) onToast(`Mbote ${user.firstName} !`, "success");
                onComplete(user);
            } else {
                setError("Identifiants incorrects.");
            }
        } catch (err) {
            setError("Une erreur est survenue lors de la connexion.");
        } finally {
            setIsLoading(false);
        }
    };

    // --- LOGIC: REGISTER ---
    const validateStep = () => {
        if (regStep === 1) {
            if (!formData.firstName || !formData.lastName || !formData.phone) {
                setError("Veuillez remplir les informations d'identité.");
                return false;
            }
        } else if (regStep === 2) {
            if (!formData.email || !registerPassword) {
                setError("Email et mot de passe requis.");
                return false;
            }
            if (registerPassword.length < 6) {
                setError("Le mot de passe doit faire au moins 6 caractères.");
                return false;
            }
        } else if (regStep === 3) {
            if (!formData.address) {
                setError("L'adresse est requise pour la collecte des déchets.");
                return false;
            }
        }
        return true;
    };

    const nextStep = () => {
        if (validateStep()) {
            setRegStep(prev => prev + 1);
            setError(null);
        }
    };

    const handleRegisterSubmit = async () => {
        if (!validateStep()) return;
        setIsLoading(true);
        setError(null);

        try {
            // Appel à l'API réelle (Supabase Auth + Profiles)
            const newUser = await UserAPI.register(formData as User, registerPassword);
            if (onToast) onToast("Compte créé avec succès !", "success");
            onComplete(newUser);
        } catch (err: any) {
            setError(err.message || "Erreur lors de la création du compte.");
        } finally {
            setIsLoading(false);
        }
    };

    // --- RENDERS ---

    const renderLogin = () => {
        const formattedDate = currentTime.toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });
        const displayTime = currentTime.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' });

        return (
            <div className="flex items-center justify-center min-h-screen bg-[#F5F7FA] p-4">
                <div className="relative w-full max-w-md bg-white rounded-[2.5rem] shadow-2xl flex flex-col p-8 space-y-6 animate-scale-up border border-white">
                    <div className="text-center">
                        <span className="text-[#00C853] font-black italic tracking-widest text-[10px] bg-green-50 px-3 py-1 rounded-full border border-green-100 uppercase">Connexion</span>
                        <h2 className="text-3xl font-black text-gray-800 mt-2 mb-4 tracking-tighter uppercase">KIN ECO-MAP</h2>
                    </div>

                    <div className="bg-gray-50 rounded-2xl p-3 flex items-center justify-between border border-gray-100">
                        <div className="flex items-center gap-3 text-gray-600"><Clock size={18} className="text-gray-400" /><span className="font-bold text-xs">{formattedDate}</span></div>
                        <div className="bg-[#00C853] px-2 py-1 rounded-md text-[10px] text-white font-bold">{displayTime}</div>
                    </div>

                    <form onSubmit={handleLoginSubmit} className="space-y-4">
                        {error && <div className="text-red-500 text-xs text-center bg-red-50 p-3 rounded-xl border border-red-100 flex items-center justify-center gap-2 animate-shake"><AlertCircle size={14} /> {error}</div>}

                        <div className="space-y-3">
                            <div className="bg-gray-50 rounded-xl flex items-center border border-gray-200 focus-within:border-[#00C853] pr-3 group transition-all">
                                <div className="pl-3 text-gray-400 group-focus-within:text-[#00C853]"><UserIcon size={18} /></div>
                                <input required type="text" placeholder="Email ou Téléphone" value={loginIdentifier} onChange={(e) => setLoginIdentifier(e.target.value)} className="bg-transparent w-full p-4 text-sm text-gray-800 outline-none" />
                            </div>
                            <div className="bg-gray-50 rounded-xl flex items-center border border-gray-200 focus-within:border-[#00C853] pr-3 group transition-all">
                                <div className="pl-3 text-gray-400 group-focus-within:text-[#00C853]"><Lock size={18} /></div>
                                <input required type={showPassword ? "text" : "password"} placeholder="Mot de passe" value={loginPassword} onChange={(e) => setLoginPassword(e.target.value)} className="bg-transparent w-full p-4 text-sm text-gray-800 outline-none" />
                                <button type="button" onClick={() => setShowPassword(!showPassword)}>{showPassword ? <EyeOff size={18} className="text-gray-400" /> : <Eye size={18} className="text-gray-400" />}</button>
                            </div>
                        </div>

                        <button type="submit" disabled={isLoading} className="w-full bg-gradient-to-r from-[#00C853] to-[#009624] text-white font-black py-4 rounded-2xl shadow-lg flex items-center justify-center gap-2 uppercase tracking-wide text-sm transform active:scale-95 transition-all">
                            {isLoading ? <Loader2 className="animate-spin" /> : 'Se Connecter'}
                        </button>
                    </form>

                    <div className="flex justify-between items-center pt-2 border-t border-gray-100">
                        <button onClick={onBackToLanding} className="flex items-center gap-2 text-gray-500 hover:text-gray-800 text-xs font-bold transition-colors"><Home size={14} /> Accueil</button>
                        <button onClick={() => setShowLogin(false)} className="text-[#2962FF] hover:text-blue-700 text-xs font-bold transition-colors">Créer un compte</button>
                    </div>
                </div>
            </div>
        );
    };

    if (showLogin) return renderLogin();

    return (
        <div className="h-screen bg-[#F5F7FA] flex flex-col md:items-center md:justify-center transition-all duration-500">
            <div className="w-full h-full md:max-w-md md:h-[90vh] md:max-h-[850px] md:shadow-2xl md:rounded-[2.5rem] overflow-hidden relative flex flex-col bg-white">

                {/* Progress Bar & Back */}
                <div className="p-6 flex items-center shrink-0 bg-white">
                    <button onClick={() => regStep > 1 ? setRegStep(s => s - 1) : onBackToLanding()} className="p-3 bg-gray-50 rounded-full text-gray-600 hover:bg-gray-100 transition-colors">
                        <ArrowLeft size={20} />
                    </button>
                    <div className="ml-4 flex-1 h-1.5 bg-gray-100 rounded-full overflow-hidden">
                        <div className="h-full bg-[#00C853] transition-all duration-500 shadow-[0_0_10px_rgba(0,200,83,0.4)]" style={{ width: `${(regStep / 3) * 100}%` }}></div>
                    </div>
                    <span className="ml-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">{regStep}/3</span>
                </div>

                <div className="flex-1 overflow-y-auto no-scrollbar p-8 space-y-6">
                    <div className="animate-fade-in-up">
                        <h2 className="text-3xl font-black text-gray-900 tracking-tight leading-none mb-2">
                            {regStep === 1 ? "Commençons" : regStep === 2 ? "Sécurisez" : "Finalisez"}
                            <br/><span className="text-[#00C853]">votre accès.</span>
                        </h2>
                        <p className="text-sm text-gray-500 font-medium">
                            {regStep === 1 ? "Entrez vos informations d'identité." : regStep === 2 ? "Configurez vos identifiants de connexion." : "Renseignez votre adresse de collecte."}
                        </p>
                    </div>

                    {error && <div className="text-red-500 text-xs bg-red-50 p-3 rounded-xl border border-red-100 flex items-center gap-2 animate-shake"><AlertCircle size={14} /> {error}</div>}

                    <div className="space-y-4">
                        {/* STEP 1: IDENTITY */}
                        {regStep === 1 && (
                            <div className="space-y-4 animate-fade-in">
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-1">
                                        <label className="text-[10px] font-bold text-gray-400 uppercase ml-1">Prénom</label>
                                        <input placeholder="Ex: Jean" className="w-full p-4 rounded-2xl bg-gray-50 border border-gray-100 outline-none focus:ring-2 focus:ring-[#00C853] font-medium transition-all" value={formData.firstName} onChange={(e) => updateData('firstName', e.target.value)} />
                                    </div>
                                    <div className="space-y-1">
                                        <label className="text-[10px] font-bold text-gray-400 uppercase ml-1">Nom</label>
                                        <input placeholder="Ex: Kabeya" className="w-full p-4 rounded-2xl bg-gray-50 border border-gray-100 outline-none focus:ring-2 focus:ring-[#00C853] font-medium transition-all" value={formData.lastName} onChange={(e) => updateData('lastName', e.target.value)} />
                                    </div>
                                </div>
                                <div className="space-y-1">
                                    <label className="text-[10px] font-bold text-gray-400 uppercase ml-1">N° de téléphone</label>
                                    <div className="relative">
                                        <Phone size={18} className="absolute left-4 top-4 text-gray-400" />
                                        <input type="tel" placeholder="081 234 5678" className="w-full pl-12 pr-4 py-4 rounded-2xl bg-gray-50 border border-gray-100 outline-none focus:ring-2 focus:ring-[#00C853] font-medium transition-all" value={formData.phone} onChange={(e) => updateData('phone', e.target.value)} />
                                    </div>
                                </div>
                            </div>
                        )}

                        {/* STEP 2: AUTH */}
                        {regStep === 2 && (
                            <div className="space-y-4 animate-fade-in">
                                <div className="space-y-1">
                                    <label className="text-[10px] font-bold text-gray-400 uppercase ml-1">Adresse Email</label>
                                    <div className="relative">
                                        <Mail size={18} className="absolute left-4 top-4 text-gray-400" />
                                        <input type="email" placeholder="nom@exemple.com" className="w-full pl-12 pr-4 py-4 rounded-2xl bg-gray-50 border border-gray-100 outline-none focus:ring-2 focus:ring-[#00C853] font-medium transition-all" value={formData.email} onChange={(e) => updateData('email', e.target.value)} />
                                    </div>
                                </div>
                                <div className="space-y-1">
                                    <label className="text-[10px] font-bold text-gray-400 uppercase ml-1">Mot de passe</label>
                                    <div className="relative">
                                        <Lock size={18} className="absolute left-4 top-4 text-gray-400" />
                                        <input type={showPassword ? "text" : "password"} placeholder="6 caractères min." className="w-full pl-12 pr-12 py-4 rounded-2xl bg-gray-50 border border-gray-100 outline-none focus:ring-2 focus:ring-[#00C853] font-medium transition-all" value={registerPassword} onChange={(e) => { setRegisterPassword(e.target.value); setError(null); }} />
                                        <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-4 top-4 text-gray-400">{showPassword ? <EyeOff size={18} /> : <Eye size={18} />}</button>
                                    </div>
                                </div>
                            </div>
                        )}

                        {/* STEP 3: PROFILE & LOCATION */}
                        {regStep === 3 && (
                            <div className="space-y-4 animate-fade-in">
                                <div className="bg-blue-50 p-5 rounded-2xl border border-blue-100 space-y-3">
                                    <p className="text-[10px] text-blue-600 font-bold uppercase tracking-widest">Type de ménage / structure</p>
                                    <div className="grid grid-cols-2 gap-2">
                                        <button onClick={() => updateData('type', UserType.CITIZEN)} className={`p-3 rounded-xl border text-xs font-bold transition-all ${formData.type === UserType.CITIZEN ? 'bg-white border-blue-500 text-blue-600 shadow-sm' : 'bg-transparent border-blue-100 text-blue-400'}`}>Eco-Citoyen</button>
                                        <button onClick={() => updateData('type', UserType.BUSINESS)} className={`p-3 rounded-xl border text-xs font-bold transition-all ${formData.type === UserType.BUSINESS ? 'bg-white border-blue-500 text-blue-600 shadow-sm' : 'bg-transparent border-blue-100 text-blue-400'}`}>Entreprise</button>
                                    </div>
                                </div>
                                <div className="space-y-1">
                                    <label className="text-[10px] font-bold text-gray-400 uppercase ml-1">Adresse de collecte</label>
                                    <div className="relative">
                                        <MapPin size={18} className="absolute left-4 top-4 text-gray-400" />
                                        <input placeholder="N°, Avenue, Quartier, Commune" className="w-full pl-12 pr-4 py-4 rounded-2xl bg-gray-50 border border-gray-100 outline-none focus:ring-2 focus:ring-[#00C853] font-medium transition-all" value={formData.address} onChange={(e) => updateData('address', e.target.value)} />
                                    </div>
                                    <p className="text-[10px] text-gray-400 mt-2 italic px-1">Cette adresse permet aux collecteurs de vous localiser précisément sur la carte.</p>
                                </div>
                            </div>
                        )}

                        <div className="pt-4">
                            <button 
                                onClick={regStep === 3 ? handleRegisterSubmit : nextStep} 
                                disabled={isLoading} 
                                className="w-full py-5 bg-[#00C853] text-white rounded-2xl font-black shadow-xl shadow-green-500/20 flex items-center justify-center gap-2 transform active:scale-95 transition-all text-lg"
                            >
                                {isLoading ? <Loader2 className="animate-spin" /> : regStep === 3 ? "CRÉER MON COMPTE" : "SUIVANT"}
                                {!isLoading && <ChevronRight />}
                            </button>
                        </div>
                    </div>

                    <div className="text-center pt-4">
                        <button onClick={() => setShowLogin(true)} className="text-gray-500 font-bold text-sm">Déjà membre ? <span className="text-[#2962FF]">Se connecter</span></button>
                    </div>

                    {regStep === 3 && (
                        <div className="bg-gray-50 p-4 rounded-2xl text-[10px] text-gray-400 leading-relaxed text-center">
                            En cliquant sur Créer mon compte, vous acceptez nos <button onClick={() => setLegalModalType('terms')} className="text-blue-500 font-bold hover:underline">CGU</button> et notre <button onClick={() => setLegalModalType('privacy')} className="text-blue-500 font-bold hover:underline">Politique de Confidentialité</button>.
                        </div>
                    )}
                </div>
            </div>
