    );
}

import React, { useState, useEffect, useRef } from 'react';
import { Onboarding } from './components/Onboarding';
import { LandingPage } from './components/LandingPage';
import { Dashboard } from './components/Dashboard';
import { MapView } from './components/Map';
import { Academy } from './components/Academy';
import { Marketplace } from './components/Marketplace'; 
import { Profile } from './components/Profile';
import { Layout } from './components/Layout';
import { Subscription } from './components/Subscription';
import { Planning } from './components/Planning';
import { Notifications } from './components/Notifications';
import { Settings } from './components/Settings';
import { AdminUsers } from './components/AdminUsers';
import { AdminAds } from './components/AdminAds';
import { AdminSubscriptions } from './components/AdminSubscriptions';
import { AdminVehicles } from './components/AdminVehicles';
import { AdminAcademy } from './components/AdminAcademy';
import { AdminPermissions } from './components/AdminPermissions';
import { CollectorJobs } from './components/CollectorJobs';
import { SplashScreen } from './components/SplashScreen';
import { User, AppView, Theme, SubscriptionPlan, Language, NotificationItem, SystemSettings } from './types';
import { SettingsAPI, UserAPI } from './services/api';

const DEFAULT_PLANS: SubscriptionPlan[] = [
    { id: 'standard', name: 'Standard', priceUSD: 10, schedule: 'Mardi & Samedi', features: ['2 jours / semaine', 'Mardi & Samedi', 'Suivi basique'] },
    { id: 'plus', name: 'Plus', priceUSD: 15, popular: true, schedule: 'Mardi, Jeudi & Samedi', features: ['3 jours / semaine', 'Mar, Jeu, Sam', 'Points doublés'] },
    { id: 'premium', name: 'Premium', priceUSD: 20, schedule: 'Lun, Mer, Ven & Dim', features: ['4 jours / semaine', 'Lun, Mer, Ven, Dim', 'Certificat Eco', 'Support VIP'] },
    { id: 'special', name: 'Spécial / Kilo', priceUSD: 0, isVariable: true, schedule: 'Sur demande', features: ['Paiement à la pesée', 'Idéal gros volumes', 'Horaires flexibles'] },
];

function App() {
    const [loading, setLoading] = useState(true);
    const [user, setUser] = useState<User | null>(() => {
        try {
            const savedUser = localStorage.getItem('kinecomap_user');
            return savedUser ? JSON.parse(savedUser) : null;
        } catch (e) { return null; }
    });

    const historySupported = useRef(true);
    const [history, setHistory] = useState<AppView[]>(() => {
        try {
            if (typeof window !== 'undefined' && window.history && window.history.state && window.history.state.history) {
                return window.history.state.history;
            }
        } catch (e) { historySupported.current = false; }
        return user ? [AppView.DASHBOARD] : [AppView.LANDING];
    });

    const view = history[history.length - 1] || AppView.LANDING;
    const [theme, setTheme] = useState<Theme>('light');
    const [language, setLanguage] = useState<Language>('fr');
    const [isRefreshing, setIsRefreshing] = useState(false);
    const [onboardingStartWithLogin, setOnboardingStartWithLogin] = useState(false);

    const [systemSettings, setSystemSettings] = useState<SystemSettings>({
        maintenanceMode: false,
        supportEmail: 'support@kinecomap.cd',
        appVersion: '1.0.3',
        force2FA: false,
        sessionTimeout: 60,
        passwordPolicy: 'strong',
        marketplaceCommission: 0.05
    });

    const [notifications, setNotifications] = useState<NotificationItem[]>([
        { id: '1', title: 'Bienvenue', message: 'Bienvenue sur KIN ECO-MAP ! Complétez votre profil pour commencer.', type: 'info', time: 'À l\'instant', read: false, targetUserId: 'ALL' }
    ]);

    const [exchangeRate, setExchangeRate] = useState(2800);
    const [plans, setPlans] = useState<SubscriptionPlan[]>(DEFAULT_PLANS);
    const [appLogo, setAppLogo] = useState('./logo.png');

    const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' | 'info'; visible: boolean }>({
        message: '', type: 'success', visible: false
    });

    useEffect(() => {
        const loadInitData = async () => {
            const settings = await SettingsAPI.get();
            setSystemSettings(settings);
            setTimeout(() => setLoading(false), 2500);
        };
        loadInitData();
    }, []);

    // Synchronisation du thème avec le body HTML
    useEffect(() => {
        if (theme === 'dark') {
            document.body.classList.add('dark');
        } else {
            document.body.classList.remove('dark');
        }
    }, [theme]);

    const navigateTo = (newView: AppView) => {
        if (newView !== view) {
            const newStack = [...history, newView];
            setHistory(newStack);
            if (historySupported.current) {
                window.history.pushState({ history: newStack }, '', `#${newView}`);
            }
        }
    };

    const goBack = () => {
        if (history.length > 1) {
            setHistory(prev => prev.slice(0, -1));
        }
    };

    const handleShowToast = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
        setToast({ message, type, visible: true });
        setTimeout(() => setToast(prev => ({ ...prev, visible: false })), 3000);
    };

    const handleLogout = () => {
        setUser(null);
        setHistory([AppView.LANDING]);
        localStorage.removeItem('kinecomap_user');
        handleShowToast("Déconnexion réussie", "info");
    };

    const handleNotify = (targetId: string | 'ADMIN' | 'ALL', title: string, message: string, type: 'info' | 'success' | 'warning' | 'alert') => {
        const newNotif: NotificationItem = {
            id: Date.now().toString(),
            title, message, type, time: 'À l\'instant', read: false, targetUserId: targetId
        };
        setNotifications([newNotif, ...notifications]);
    };

    const renderContent = () => {
        if (!user) {
            if (view === AppView.LANDING) {
                return (
                    <LandingPage 
                        onStart={() => {
                            setOnboardingStartWithLogin(false);
                            navigateTo(AppView.ONBOARDING);
                        }} 
                        onLogin={() => {
                            setOnboardingStartWithLogin(true);
                            navigateTo(AppView.ONBOARDING);
                        }}
                    />
                );
            }
            if (view === AppView.ONBOARDING) {
                return (
                    <Onboarding 
                        initialShowLogin={onboardingStartWithLogin}
                        onBackToLanding={() => {
                            setHistory([AppView.LANDING]);
                        }}
                        onComplete={(data) => {
                            const authenticatedUser = data as User;
                            setUser(authenticatedUser);
                            localStorage.setItem('kinecomap_user', JSON.stringify(authenticatedUser));
                            setHistory([AppView.DASHBOARD]);
                        }} 
                        appLogo={appLogo} 
                        onToast={handleShowToast} 
                    />
                );
            }
            return null;
        }

        switch (view) {
            case AppView.DASHBOARD: 
                return <Dashboard user={user} onChangeView={navigateTo} onToast={handleShowToast} />;
            case AppView.MAP: 
                return <MapView user={user} onBack={goBack} />;
            case AppView.ACADEMY: 
                return <Academy onBack={goBack} />;
            case AppView.MARKETPLACE: 
                return <Marketplace user={user} onBack={goBack} systemSettings={systemSettings} onToast={handleShowToast} />;
            case AppView.PROFILE: 
                return <Profile user={user} theme={theme} onToggleTheme={() => setTheme(t => t === 'light' ? 'dark' : 'light')} onBack={goBack} onLogout={handleLogout} onManageSubscription={() => navigateTo(AppView.SUBSCRIPTION)} onSettings={() => navigateTo(AppView.SETTINGS)} onUpdateProfile={p => setUser({ ...user, ...p })} onToast={handleShowToast} />;
            case AppView.SUBSCRIPTION:
                return <Subscription user={user} onBack={goBack} onUpdatePlan={(p) => { setUser({...user, subscription: p}); handleShowToast("Abonnement mis à jour", "success"); goBack(); }} plans={plans} exchangeRate={exchangeRate} onToast={handleShowToast} />;
            case AppView.PLANNING:
                return <Planning onBack={goBack} />;
            case AppView.NOTIFICATIONS:
                return <Notifications onBack={goBack} notifications={notifications} onMarkAllRead={() => setNotifications(prev => prev.map(n => ({...n, read: true})))} />;
            case AppView.SETTINGS:
                return <Settings user={user} theme={theme} onToggleTheme={() => setTheme(t => t === 'light' ? 'dark' : 'light')} onBack={goBack} onLogout={handleLogout} currentLanguage={language} onLanguageChange={setLanguage} onToast={handleShowToast} />;
            case AppView.COLLECTOR_JOBS:
                return <CollectorJobs user={user} onBack={goBack} onNotify={handleNotify} onToast={handleShowToast} />;

            // ADMIN VIEWS
            case AppView.ADMIN_USERS:
                return <AdminUsers onBack={goBack} currentUser={user} onNotify={handleNotify} onToast={handleShowToast} />;
            case AppView.ADMIN_ADS:
                return <AdminAds onBack={goBack} onToast={handleShowToast} />;
            case AppView.ADMIN_SUBSCRIPTIONS:
                return <AdminSubscriptions onBack={goBack} plans={plans} exchangeRate={exchangeRate} onUpdatePlan={(p) => setPlans(plans.map(pl => pl.id === p.id ? p : pl))} onUpdateExchangeRate={setExchangeRate} currentLogo={appLogo} onUpdateLogo={setAppLogo} systemSettings={systemSettings} onUpdateSystemSettings={setSystemSettings} onToast={handleShowToast} />;
            case AppView.ADMIN_VEHICLES:
                return <AdminVehicles onBack={goBack} onToast={handleShowToast} />;
            case AppView.ADMIN_ACADEMY:
                return <AdminAcademy onBack={goBack} onToast={handleShowToast} />;
            case AppView.ADMIN_PERMISSIONS:
                return <AdminPermissions onBack={goBack} onToast={handleShowToast} />;

            default: 
                return <Dashboard user={user} onChangeView={navigateTo} onToast={handleShowToast} />;
        }
    };

    if (loading) return <SplashScreen appLogo={appLogo} />;

    // Si on est sur la Landing ou l'Onboarding sans user, on ne rend pas le Layout
    if (view === AppView.LANDING || (!user && view === AppView.ONBOARDING)) return renderContent();

    return (
        <Layout 
            currentView={view} 
            onChangeView={navigateTo}
            onLogout={handleLogout} 
            onRefresh={() => {
                setIsRefreshing(true);
                setTimeout(() => setIsRefreshing(false), 1500);
            }}
            isRefreshing={isRefreshing}
            user={user}
            unreadNotifications={notifications.filter(n => !n.read).length}
            appLogo={appLogo}
            toast={toast}
            onCloseToast={() => setToast(prev => ({...prev, visible: false}))}
        >
            {renderContent()}
        </Layout>
    );
}

export default App;

import React, { useState, useEffect } from 'react';
import { Home, Map as MapIcon, GraduationCap, User, LogOut, Settings, RotateCw, Loader2, Users, ClipboardList, Megaphone, PieChart, CreditCard, Truck, BookOpen, WifiOff, ShoppingBag, CheckCircle, AlertCircle, Info, X, Shield, Factory } from 'lucide-react';
